/* cotTruyen q13 (64 chương) — engine-API cotTruyen */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q13"]=window.__LIBQ["tien-nghich"]["q13"]||{};window.__LIBQ["tien-nghich"]["q13"]["cotTruyen"]=[{"chuong":1387,"tieuDe":"Về Nhà!","tomTat":"Vương Lâm từ cổ mộ bước vào La Thiên Tinh Vực, uy áp quét ngang toàn bộ tinh vực. Lỗ Phu Tử — cao thủ Không Niết Sơ Kỳ đang chữa thương trong tinh trận phía tây bắc — cảm nhận được, sắc mặt đại biến, ra lệnh bốn thuộc hạ bày La Thiên Huyễn Kính để quan sát. Tấm gương chiếu ra hình Vương Lâm áo trắng tóc trắng bay trong tinh không, nhưng Vương Lâm phát hiện bị dòm ngó, dùng lôi đồ mắt phải phá hủy tấm kính từ xa, lôi đình tràn ngập khiến bốn người phun máu. Viêm Lôi Tử nhận ra Vương Lâm nhưng tự nhủ không có ân oán nên bình tĩnh lại. Liệt Vân Tử hoảng sợ nhớ lần bị đàn áp ở Chu Tước Thánh Tông rồi thở dài. Huyết Thần Tử không thể tin kẻ năm xưa mình truy sát nay lại mạnh đến vậy, im lặng ngồi xuống không dám ra ngoài. Hướng Vân Đông đạo tâm bị nứt, lo sợ ân oán Thất Tịch Thuật năm xưa, vội từ biệt Lỗ Phu Tử về Hướng gia báo tin chuẩn bị. Lỗ Phu Tử nhớ lại từng kết bạn với Vương Lâm ở vùng đất Cổ Thần, thừa nhận Vương Lâm tuy chưa đạt bước thứ ba nhưng bản thân cũng không nắm chắc chiến thắng."},{"chuong":1388,"tieuDe":"La Thiên Chuẩn Bị Cho Cuộc Chiến","tomTat":"Vương Lâm trở về La Thiên Tinh Vực, bình tĩnh nhận ra có người dò xét tu vi nhưng tự tin không lo lắng. Hắn bắt gặp đội gần trăm tu sĩ do Chiến Không Liệt (Tịnh Niết viên mãn) chỉ huy đang kéo tu chân tinh phục vụ chuẩn bị chiến tranh tứ đại tinh vực, Vân Hải cầm đầu, kế hoạch do Lỗ Phu Tử cùng ba tinh vực khác định ra. Vương Lâm nhận ra Chiến Không Liệt nhưng không lên tiếng, nhớ lại chuyện Lôi Trì năm xưa rồi mỉm cười bay đi. Chiến Không Liệt sau đó nhận ra người áo trắng chính là tôn chủ năm xưa, kích động đuổi theo nhưng không kịp, đau khổ vái tinh không rồi rời đi. Sâu trong La Thiên, trên Thanh Linh Tinh hoang vu, lão già Tạ Thanh mặc văn sam đã ngồi trên đỉnh Hoành Vân sơn hơn tám trăm năm chờ sư tôn — người từng nói cả đời không có đệ tử nhưng thu nhận hắn vì có duyên, chỉ cho một hồi cảm ngộ. Tạ Thanh kiên quyết bảo vệ tinh cầu cho sư tôn, từ chối lệnh Lôi Tiên Điện thu tinh cầu trong ba ngày. Cuối chương cơn mưa lớn ập đến, tiếng thở dài từ thiên địa vang lên gọi tên Tạ Thanh, hàm ý sư tôn đã trở về."},{"chuong":1389,"tieuDe":"Gặp Lại Cố Nhân","tomTat":"Vương Lâm trở lại Thanh Linh Tinh sau tám trăm năm xa cách, gặp lại ký danh đệ tử Tạ Thanh đang ngồi tu trên đỉnh Hoành Vân Sơn. Hắn nhận ra Tạ Thanh đang đi con đường tu hồn — chỉ tu ý cảnh thuần túy, không có nguyên thần hay nguyên anh, ý cảnh đạt Tịnh Niết sơ khuy quy tắc. Vương Lâm giảng lý phản phác quy chân, dặn Tạ Thanh phải bỏ hết thân thể và pháp thuật, chỉ còn hồn phách thì hãy tới tìm mình. Hắn thu toàn bộ nước mưa gần nửa Thanh Linh Tinh ngưng tụ thành vũ kiếm vạn trượng cắm trên đỉnh Hoành Vân Sơn, chú nhập Cổ Thần lực cùng lôi hỏa bổn nguyên và khí thế Đạo Cổ để trấn hộ tinh cầu, tuyên bố đây là lễ nhập môn cho Tạ Thanh khi minh ngộ. Rời Thanh Linh Tinh, Vương Lâm hướng tới tu chân tinh Hướng gia để thanh toán chuyện cũ Thất Tịch Thuật, đây là việc thứ hai trong bốn việc hắn muốn làm tại La Thiên. Mấy canh giờ sau, nhóm hơn mười tu sĩ Lôi Tiên Điện phụng mệnh La Thiên lão tổ tìm tu chân tinh tạo Tinh Tổn Thất Kiếp Trận, nhắm Thanh Linh Tinh nhưng bị kiếm ý xông tới, cả nhóm phun máu lùi lại. Lỗ Phu Tử lén xuất hiện sau khi Vương Lâm rời đi, tung một chỉ thăm dò vũ kiếm, hoảng sợ phát hiện khí tức giống Cổ Thần nhưng hoàn toàn khác và bên trong chứa hai đạo bổn nguyên."},{"chuong":1390,"tieuDe":"Hôm Nay Mây Giăng Mưa Đổ","tomTat":"Lỗ Phu Tử sau khi chứng kiến hai đạo bổn nguyên của Vương Lâm, tuy kinh hãi nhưng nhanh chóng trấn tĩnh, nhận định hắn chưa đạt bước thứ ba nên tự tin Không Niết Sơ Kỳ đủ sức đối phó, rồi rời đi coi vạn vật như kiến hôi. Hướng Vân Đông mang tin Vương Lâm trở về với tu vi khủng khiếp khiến cả Hướng gia chấn động, đại trưởng lão và gia chủ lập tức phát động Đông Lâm huyết lệnh phòng thủ toàn diện. Chương hé lộ Hướng gia là bá chủ âm thầm trên Đông Lâm Tinh, truyền thừa từ thượng cổ, tam đại gia tộc Hứa, Lữ, Lưu thực chất đều là phân chi của Hướng gia. Đông Lâm Tinh là tinh cầu di chuyển, thần thức không quét được, có mấy chục tiểu tinh vờn quanh và trận pháp bao phủ. Lão tổ đời đầu Hướng gia nằm trong quan tài giữa biển đầu lâu vùng cực tây, nhận định sinh cơ Vương Lâm rất hợp có thể giúp hắn trở lại rất lâu, cho rằng Lỗ Phu Tử phóng đại và coi Vương Lâm không đáng ngại. Tuy nhiên ngay lúc đó, Vương Lâm mặc bạch y đã xuất hiện ở tinh không bên ngoài Đông Lâm Tinh, hồi tưởng năm xưa cùng Thanh Thủy lần đầu tới đây, hàn quang ngập trời tỏa ra trong mắt."},{"chuong":1391,"tieuDe":"Đông Lâm Tinh Hướng Gia!","tomTat":"Vương Lâm đứng trước Đông Lâm Tinh, hồi tưởng mối hận năm xưa bị lão tổ Hướng gia dùng Thất Tịch Thuật lừa gạt cướp toàn bộ sức sống, gián tiếp khiến Lý Mộ Uyển hồn bay phách tán. Hắn nhận ra Thất Tịch Thuật hoàn toàn không có khả năng hồi sinh người và nếu không có Tị Thiên Quan thì hy vọng hồi sinh Lý Mộ Uyển cũng bị dập tắt. Phẫn nộ ngợp trời, Vương Lâm bước một bước rút ngắn mấy vạn trượng rồi há miệng phát tiếng rống kinh thiên hóa lôi đình, phá hủy chín tu chân tinh bên ngoài, giết sạch tu sĩ và 27 lão già trận pháp trên đó. Trên Đông Lâm Tinh, mặt đất nứt, núi tan, biển phía bắc dâng sóng ngàn trượng. Hai lão già áo đen ở cực tây bị tiếng rống đánh, một người thân thể tan vỡ chết, người còn lại phun máu hoảng sợ rút ngọc giản đen ra lệnh toàn Đông Lâm Tinh bày trận. Không gian biển đầu người sâu dưới lòng đất bị tách vết nứt, quan tài màu vàng bị đập vỡ lộ ra cánh tay khô héo bấu chặt thành quan tài. Toàn bộ Đông Lâm Tinh dàn binh bốn mặt: Lữ gia phía bắc hợp trận huyết ảnh, Hứa gia phía nam đầm máu ngàn trượng, Lưu gia phía đông trận hoa hướng dương, tiểu tinh kích hoạt cấm chế tạo lốc xoáy bao phủ. Vương Lâm lạnh lùng tuyên bố sẽ tự lôi lão tổ Hướng gia ra, ai ngăn cản đều bị chôn cùng."},{"chuong":1392,"tieuDe":"Việc Này Không Ngại!","tomTat":"Khi Vương Lâm tiến về phía Đông Lâm Tinh, Lữ gia kích hoạt đại trận phòng thủ thượng cổ gồm ba trận pháp, hàng ngàn tu sĩ trên mấy chục tiểu tinh tạo hơn chín ngàn vạn tầng hào quang bao vây. Tại trung tâm trận tinh La Thiên, Lỗ Phu Tử cùng Viêm Lôi Tử, Huyết Thần Tử, Liệt Vân Tử quan sát từ xa, Lỗ Phu Tử tự đánh giá cần hai mươi nhịp thở để phá trận. Vương Lâm kích hoạt bảy tinh điểm Cổ Thần, giải phóng khí tức Đạo Cổ — vượt trên Cổ Thần, phía sau hiện hư ảnh khổng lồ cái đầu không có mắt trái — rồi đánh ra một quyền Thần Chấn dung hợp thất tinh Cổ Thần và Đạo Cổ. Nắm tay hư ảo mấy vạn trượng phá vỡ toàn bộ hào quang, đánh nát mấy chục tiểu tinh, tiêu diệt tu sĩ duy trì trận. Lữ gia hiến tế gần một vạn tu sĩ tạo huyết ảnh trận linh đối kháng nhưng bị đánh nổ tung ngay lập tức. Quyền Thần Chấn nện xuống phía bắc Đông Lâm Tinh tạo hố sâu mấy vạn trượng, gần một vạn tu sĩ tử vong. Toàn bộ chỉ diễn ra trong tám nhịp thở. Lỗ Phu Tử kinh hãi thừa nhận phán đoán sai lầm, bỏ đi hoàn toàn đánh giá trước đó, đặt Vương Lâm lên vị trí ngang hàng với mình."},{"chuong":1393,"tieuDe":"Sai Lầm Của Lỗ Phu Tử!","tomTat":"Sau quyền Đạo Cổ Thần Chấn diệt Lữ gia, toàn bộ Đông Lâm Tinh ngập trong nước biển, núi vỡ đất nứt. Ba đại gia tộc còn lại chấn động tuyệt vọng, tất cả đưa mắt nhìn về phía cực tây chờ quyết định của lão tổ Hướng gia. Vương Lâm áo trắng xuất hiện trên bầu trời, quát lão tổ Hướng gia chui ra khỏi quan tài. Lão tổ Hướng gia gào lệnh tử chiến đến cùng, khiến toàn bộ tộc nhân Hướng gia và Hứa gia đồng thời mất lý trí, hai mắt đỏ bừng điên cuồng lao tới Vương Lâm. Gần một vạn tu sĩ Lưu gia thi triển cấm thuật Huyết Quỳ Thuật — đầu vỡ tung dung hợp thần chú tạo cột sáng vạn trượng chứa thân ảnh không đầu mặc giáp cầm trường thương, uy lực gần bằng Không Niết Sơ Kỳ bước thứ ba, nhưng bị Vương Lâm một chưởng đỡ, lực phản chấn tách phần phía đông Đông Lâm Tinh thành mảnh vỡ bay vào tinh hải. Vương Lâm triển khai Hư Hỏa thiêu tất cả tu sĩ điên cuồng lao tới thành tro bụi không ngoại lệ. Hắn bước tới cực tây, vào không gian dưới lòng đất nơi quan tài lão tổ Hướng gia, phá tan sóng chất lỏng tử khí. Lão tổ Hướng gia cánh tay khô héo vịn thành quan tài, tuyên bố Viễn cổ chiếu viết người hủy diệt Đông Lâm Tinh bị tru di cửu tộc, rồi giãy giụa ngồi dậy."},{"chuong":1394,"tieuDe":"Viễn Cổ Chiếu Viết","tomTat":"Vương Lâm đối diện lão tổ Hướng gia — kẻ lộ thân phận thật là Đông Lâm Thái, tộc nhân phân hệ gia tộc Đông Lâm viễn cổ, tu vi Thiên Nhân Đệ Ngũ Suy. Vương Lâm tung hai chỉ phá nát tứ chi, triển khai Sưu Hồn Thuật tìm câu trả lời rồi nổ đầu kết liễu. Đông Lâm Thái trước khi chết gào lên Vương Lâm vi phạm chiếu viết gia tộc, dọa tru di cửu tộc. Cánh cửa vàng khắc chữ Đông Lâm xuất hiện giữa không trung, lão già mặc kim bào thi triển Huyễn Thần Thuật tạo người khổng lồ kim giáp ngàn trượng tuyên ba tội trạng, vung đại kiếm vàng tấn công. Vương Lâm một chỉ kết hợp Đạo cổ lực, lôi hỏa bổn nguyên cùng huyết kiếm phá tan Huyễn Thần Thuật, bức lão già nửa bước thứ ba trọng thương, tuyên bố đã giết đủ rồi bước vào tinh không rời đi. Nam tử trung niên Đông Lâm gia thứ hai xuất hiện, tiết lộ trên người Vương Lâm có hai luồng khí tức cao thủ bước thứ ba và Vương Lâm chỉ lộ một phần nhỏ thực lực. Trong thế giới đóng băng phía sau cánh cửa vàng, Thần trưởng lão — nữ tử mang khí tức Cổ Thần — bất ngờ mở mắt xuất quan, được hai tu sĩ kim bào cung kính nghênh đón."},{"chuong":1395,"tieuDe":"Thần Trưởng Lão!","tomTat":"Nữ tử tuyệt sắc (Nữ Cổ Thần thất tinh) tỉnh giấc trên đại lục bị băng bao phủ, mi tâm lộ bảy tinh điểm màu tím, thân phận nàng là đáp án cho nhiều sự kiện trước đó. Vương Lâm bước đi trong tinh không La Thiên Tinh Vực, từ trí nhớ soát hồn lão tổ Hướng gia hiểu được sự tình năm xưa: lão tổ hút sinh cơ vì dục vọng, bị gia tộc viễn cổ Đông Lâm truyền thần niệm buộc buông tha, chuyển sang hấp thu sinh cơ Cổ Thần qua linh hồn Vương Lâm. Vương Lâm đoán gia tộc viễn cổ có Cổ Thần, xác định mục tiêu thứ ba là Diêu gia và Huyết Thần Tử — lấy Cổ Yêu lực cho phân thân và xử lý nhân quả với Diêu Băng Vân. Tin tức Đông Lâm tinh sụp đổ lan khắp La Thiên Tinh Vực gây chấn động. Tây Tử Phượng tái xuất ở phía nam tinh vực — gia tộc Tây gia diệt vong trong đại chiến, lão tổ chết vì cứu nàng trên Chu Tước Tinh, nàng tự hủy dung nhan, suốt tám trăm năm dựa vào ký ức về Vương Lâm trong Lôi Tiên Giới để sống. Nàng bị nam tử trung niên Khuy Niết trung kỳ ép dùng nguyên thần rung chuyển tu chân tinh lần thứ tư dù chưa hồi phục, đành cắn môi tuân lệnh."},{"chuong":1396,"tieuDe":"Vãng Tích Hồng Nhan Mộng","tomTat":"Tây Tử Phượng dùng thần thức chấn động tu chân tinh hai lần nhằm lay chuyển quỹ đạo nhưng đều thất bại, bị lực phản chấn đánh tan thần thức, nguyên thần bị thương nặng. Sứ giả Lôi Tiên Điện mắng nàng là phế vật rồi tự mình dùng thần thức khiến tu chân tinh thoát quỹ đạo, chỉ huy gần trăm tu sĩ dùng tơ tằm bạc kéo tu chân tinh di chuyển. Lão già tu vi Khuy Niết sơ kỳ, từng được Vương Lâm mang ra khỏi Lôi Tiên Giới, tặng Tây Tử Phượng đan dược trân quý và dùng uy danh Vương Lâm trấn áp sứ giả. Vương Lâm bạch y tóc trắng bất ngờ lướt qua tinh không, uy áp khủng khiếp khiến sứ giả quỳ xuống hồn phi phách tán. Hắn nhận ra Tây Tử Phượng trong đám tu sĩ, nhìn thấy vết sẹo kinh hãi trên mặt nàng — tám trăm năm trước nàng đã tự hủy dung mạo — mà đau xót dừng lại. Vương Lâm tự xưng danh khiến cả trăm tu sĩ chấn động, nhưng Tây Tử Phượng phủ nhận danh tính, lùi bước, nước mắt trào ra lần đầu sau tám trăm năm, không muốn bị nhìn thấy trong tình cảnh chật vật dung mạo đã hủy."},{"chuong":1397,"tieuDe":"Sớm Mai Mông Lung Lệ","tomTat":"Vương Lâm nhìn Tây Tử Phượng, nhận ra nguyên thần nàng bị thương nhiều lần tích thành tật rất khó chữa, gần đây lại bị thương nặng thêm. Hắn nhận ra lão già Chu Tùng Vân chính là tu sĩ năm xưa được mình cứu khỏi Lôi Tiên Giới, Chu Tùng Vân kích động gọi hắn là ân công. Chu Tùng Vân chỉ thẳng vào nam tử trung niên sứ giả Lôi Tiên Điện đang quỳ, tố cáo hắn hết lần này đến lần khác làm khó Tây Tử Phượng khiến nguyên thần nàng bị thương nghiêm trọng. Sứ giả phản bác, tự xưng hành động vì chuẩn bị chiến tranh cho La Thiên rồi nhanh chóng lùi trăm trượng. Vương Lâm tuyên án thẳng sứ giả đáng chết vì tội làm nhục người con gái yếu đuối, chậm rãi giơ tay chuẩn bị ra tay. Sứ giả gào xin tha mạng bằng đủ lý do: đe dọa bằng danh nghĩa Lôi Tiên Điện và tứ đại tinh vực liên thủ, xin cơ hội chết trên chiến trường chống giới ngoại, xin sống thêm trăm năm — chương kết thúc khi hắn vẫn đang van xin chưa có kết quả."},{"chuong":1398,"tieuDe":"Sớm Mai Mông Lung Lệ (2)","tomTat":"Vương Lâm phất tay giết chết nam tử trung niên sứ giả Lôi Tiên Điện (tu vi Khuy Niết) — toàn thân nổ tung tiêu tan trước gần trăm tu sĩ kinh hoàng. Trước khi chết, nam tử gào rằng suốt mấy trăm năm qua nhiều người đã làm nhục Tây Tử Phượng, không chỉ riêng hắn. Vương Lâm ban một viên đan dược chứa hồn phách mãnh thú cho lão già từng bảo vệ Tây Tử Phượng, rồi đưa nàng tới một tu chân tinh hoang vắng phủ tuyết trong La Thiên Tinh Vực. Hắn dùng nguyên lực chữa lành thương thế và phục hồi dung nhan diễm lệ mà nàng đã tự phá hủy tám trăm năm trước, khiến nàng rơi nước mắt. Vương Lâm đề nghị thu nàng làm đệ tử thứ ba, sau Tạ Thành Thanh và Thập Tam — hắn không thể đáp lại tình cảm nhưng cũng nói không ra câu tuyệt tình. Sau hồi trầm mặc, Tây Tử Phượng nở nụ cười nhu hòa rồi quỳ bái sư, hành động cắt đứt chuyện cũ tám trăm năm, đau khổ nhưng giải thoát. Vương Lâm truyền nguyên lực vô biên cùng phần cảm ngộ cả đời vào cơ thể nàng, giúp tu vi từ Dương Thực đột phá qua Khuy Niết tới Tinh Tịnh Niết, rồi đặt ba đạo phong ấn áp chế tu vi bạo tăng. Thuật truyền công này ngay cả với tu vi của Vương Lâm cũng rất khó làm lại."},{"chuong":1399,"tieuDe":"Tây Tử Quên Mong Tình","tomTat":"Giữa trời tuyết, Vương Lâm ngưng tụ tuyết nhuốm máu Cổ Thần, nhập Cực Cảnh Lôi đình luyện thành thanh trường kiếm đỏ máu, tuyên bố dưới bước thứ ba không ai chịu nổi một nhát kiếm, rồi tặng Tây Tử Phượng làm bản mệnh pháp bảo. Tây Tử Phượng yên lặng nhìn Vương Lâm rời đi, trong mắt ẩn tình cảm chôn giấu tám trăm năm, tự nhủ kết cục này có lẽ là tốt nhất. Vương Lâm hé lộ rằng lúc truyền công đã đảo qua ký ức của nàng, ghi nhớ bộ dạng tất cả kẻ đã làm nhục nàng suốt tám trăm năm. Dựa vào thần thức cảm ứng, hắn phóng ra gần trăm đạo kiếm khí quét ngang La Thiên Tinh Vực — giết gia chủ Triệu gia trên Vân Động Tinh, đại trưởng lão gia tộc Đông Lai trên Thiên Mạc Tinh, thiếu tộc trưởng Lô gia trên Tử Miểu Tinh, cùng nhiều kẻ khác trên các tinh cầu, không thừa không sót. Mười một đạo kiếm khí còn xâm nhập tinh trận khổng lồ Lôi Tiên Điện giết mười một mục tiêu bên trong. Sau đó thân ảnh Vương Lâm xuất hiện bên ngoài tinh trận, chậm rãi bước tới, mỗi bước ầm vang như lôi đình, khiến vô số tu sĩ Lôi Tiên Điện nhất tề lùi lại. Lỗ Phu Tử bên trong vòng xoáy trung tâm tinh trận phát ra tiếng gào thét kinh thiên."},{"chuong":1400,"tieuDe":"Nhằm Vào Lỗ Phu Tử!","tomTat":"Vương Lâm đối đầu trực diện với Lỗ Phu Tử khi tiến vào khu vực tinh trận. Lỗ Phu Tử dồn toàn bộ tu vi Không Niết Sơ Kỳ phát ra tiếng gào thét ngăn chặn, nhưng Vương Lâm kích hoạt bảy tinh điểm Cổ Thần cùng đầu Đạo Cổ, phát tiếng rống Đạo Cổ áp đảo hoàn toàn, khiến vòng xoáy tinh trận ngừng xoay và các tu sĩ bên trong như Viêm Lôi Tử, Liệt Vân Tử, Huyết Thần Tử đều kinh hãi. Vương Lâm bước vào tinh trận, chào hỏi Viêm Lôi Tử bằng xưng hô ngang hàng, rồi chỉ thẳng vào Huyết Thần Tử tuyên bố chỉ cần người này vì hắn rất có ích cho mình. Lỗ Phu Tử hạ mình ôm quyền xin Vương Lâm nể mặt tha cho Huyết Thần Tử, nguyện nợ một ân tình, nhưng bị từ chối thẳng. Huyết Thần Tử tuyệt vọng cầu cứu Lỗ Phu Tử, hé lộ mình là người duy nhất có thể đưa Lỗ Phu Tử đến một nơi bí ẩn quan trọng. Lỗ Phu Tử nổi giận, tự phụ tu vi bước thứ ba mấy vạn năm, thách Vương Lâm giao chiến ngay trong tinh trận, và Vương Lâm lạnh lùng chấp nhận nghênh chiến."},{"chuong":1401,"tieuDe":"Hôm Nay Mây Giăng Mưa Đổ","tomTat":"Vương Lâm đối mặt Lỗ Phu Tử, hai cao thủ bước thứ ba đánh giá lẫn nhau. Lỗ Phu Tử cảm nhận chiến ý mãnh liệt từ Vương Lâm, e ngại giao chiến sẽ kích động Phong Giới Đại Trận và ảnh hưởng kế hoạch cướp hương hỏa giới ngoại, bèn đề nghị đấu văn ba hiệp: luyện khí, đấu đạo niệm, đấu thần thông. Điều kiện cược: Vương Lâm thắng thì nhận Huyết Thần Tử, thua thì phải rời La Thiên. Vương Lâm đồng ý, chọn luyện khí cho hiệp đầu. Lỗ Phu Tử biểu diễn luyện khí trước mấy vạn tu sĩ Lôi Tiên Điện, dùng tinh quang La Thiên, bụi đất vạn cổ, phong bổn nguyên và máu mấy vạn tu sĩ cùng máu bước thứ ba của mình tạo ra pháp bảo cấp Không Niết hình cây đại thụ, đặt tên La Thiên Thụ, tuyên bố sẽ mở La Thiên Tiên Bảng ban cho người giết địch nhiều nhất trong cuộc chiến giới ngoại. Vương Lâm bình tĩnh dùng lôi hỏa bổn nguyên triệt tiêu cuồng phong, thản nhiên quan sát đối thủ hoàn thành luyện khí."},{"chuong":1402,"tieuDe":"Văn Đấu","tomTat":"La Thiên Thụ hoàn thành, mấy vạn tu sĩ Lôi Tiên Điện cuồng nhiệt, nhưng Vương Lâm nhìn thấu tâm cơ ẩn giấu của Lỗ Phu Tử — phá La Thiên Thụ đồng nghĩa đối kháng chiến ý toàn La Thiên. Lỗ Phu Tử mời Vương Lâm luyện bảo vật đáp lễ, Vương Lâm một trảo phá vỡ chín tu chân tinh rút tinh chất, lần lượt dung nhập sát khí cả đời qua chín giai đoạn chiến sát từ Chu Tước Tinh tới Đông Lâm Tinh, ngưng tụ thành viên huyết tinh chứa vô số vong hồn. Huyết tinh phóng ra bức lui mấy vạn tu sĩ phun máu, Huyết Thần Tử phun máu tươi, Liệt Vân Tử hoảng sợ lùi, La Thiên Thụ chấn động suýt vỡ. Lỗ Phu Tử da đầu tê dại, thừa nhận chưa từng gặp tu sĩ có sát khí như vậy, hỏi dựa vào gì mà chỉ sát khí lại phá được La Thiên Thụ. Vương Lâm tuyên bố bảo vật không cần bổn nguyên, huyết mạch, chiến ý hay tâm cơ, chỉ sát khí cả đời cũng đủ phá hủy, thể hiện sự tự tin bá đạo tuyệt đối."},{"chuong":1403,"tieuDe":"Không Ngại Thử Một Lần","tomTat":"Lỗ Phu Tử đề nghị trận đấu thứ hai đấu đạo niệm nhưng Vương Lâm từ chối, muốn lướt qua trực tiếp giết Huyết Thần Tử đang tái nhợt phía sau. Lỗ Phu Tử bộc phát toàn bộ khí thế Không Niết sơ kỳ bước thứ ba, triệu thanh tàn kiếm từng xuyên thân Cổ Thần bát tinh Đồ Ti, biến ảo ra Phong Tiên Giới hoàn chỉnh — bổn nguyên và khởi nguồn hương hỏa của mình — rồi khởi động La Thiên đại trận gồm mấy trăm tu chân tinh vốn chuẩn bị chống giới ngoại. Lỗ Phu Tử xung phong cùng hư ảnh chúng tiên và tàn kiếm, nhưng Vương Lâm lần đầu bộ lộ hoàn toàn khí tức Cổ Thần Thất Tinh ngang bước thứ ba rồi điểm mi tâm triệu Thiên Hoàng Lô, gọi cổ nô Linh Động Thượng Nhân ra. Linh Động bạo phát khí tức chân chính bước thứ ba, hương hỏa vượt xa Lỗ Phu Tử, khiến hắn dừng lại hoàn toàn sắc mặt đại biến vì không nhận ra danh tính tu sĩ bước thứ ba này. Viêm Lôi Tử chấn động tột độ, mấy vạn năm tu đạo gộp lại cũng không bằng cú sốc hôm nay."},{"chuong":1404,"tieuDe":"Linh Động Hiện","tomTat":"Sự xuất hiện của Linh Động Thượng Nhân với tư cách nô phó bước thứ ba khiến toàn bộ phe La Thiên chấn động — Liệt Vân Tử phun máu, Huyết Thần Tử ngây ngẩn, mấy vạn tu sĩ kinh hoàng. Lỗ Phu Tử dù biết không địch nổi vẫn quyết chiến, kích hoạt tinh trận bộc phát gấp mấy chục lần bình thường, triển khai mười tám pháp bảo luyện suốt mấy vạn năm, đồng thời mấy vạn tu sĩ hô vang tặng hương hỏa lực cho hắn. Lão tổ Hướng gia cũng phóng hư ảnh tiên nhân cùng thanh tàn kiếm từ Phong Tiên Giới bức sát mi tâm Vương Lâm. Tuy nhiên Vương Lâm bình thản gọi Cổ nô Chu Cẩn, triệu hoán nô phó bước thứ ba thứ hai từ Thiên Hoàng Lô hiện thân với huyết lang mấy vạn trượng phía sau. Uy áp đồng thời của Linh Động Thượng Nhân và Chu Cẩn quét sạch Phong Tiên Giới, ép tàn kiếm nứt nẻ đến mức kiếm linh kêu thảm thiết phải run rẩy lui về. Lỗ Phu Tử vội vàng lui hơn trăm trượng, hoàn toàn mất ý chí chiến đấu, nhận ra tinh trận chưa đầy đủ thì không thể nào đối đầu cùng lúc ba tu sĩ bước thứ ba."},{"chuong":1405,"tieuDe":"Không Phải Chỉ Có Một","tomTat":"Chu Cẩn xuất hiện bên cạnh Linh Động Thượng Nhân, lộ diện là nô phó bước thứ ba thứ hai của Vương Lâm, gần đạt Không Niết Sơ Kỳ đỉnh phong. Hai khí tức bước thứ ba cùng bộc phát quét khắp La Thiên Tinh Vực tràn sang ba đại tinh vực, đẩy lùi mười tám pháp bảo và trận pháp của Lỗ Phu Tử, ý chí kháng cự của hắn triệt để sụp đổ. Trong Vân Hải tinh vực, Thủy Đạo Tử đang bế quan trong mật thất Thần Tông hoảng sợ mở mắt, còn nữ tử tuyệt mỹ bị phong ấn trong trận pháp không phản ứng gì; nam tử áo đỏ bí ẩn mà tông chủ Yêu Tông phải quỳ trước nhận xét Vương Lâm là người được chủ nhân Phong giới coi trọng. Trong Liên Minh Tinh Vực, Thanh Lâm và Tư Đồ Nam mở mắt nghi hoặc; nam tử hắc y giống hệt Vương Lâm năm xưa run lên kích động gọi Sư tôn khi cảm ứng được Vương Lâm từ cõi u minh. Tổng bộ Tu Chân Liên Minh đã bị phong kín hoàn toàn với tiếng gầm thét giết chóc vang suốt mấy trăm năm, còn tại Thi Âm Tông, một ánh mắt có thể khiến tinh không sụp đổ nhận ra Vương Lâm là người được chủ nhân Phong giới ước định. Vương Lâm bình tĩnh bước qua Lỗ Phu Tử mà không làm nhục vì nhớ ơn xưa, rồi đi tới Huyết Thần Tử; Huyết Thần Tử gầm lên giãy dụa, hai tay bắt quyết triệu hoàn yêu ảnh hư ảo."},{"chuong":1406,"tieuDe":"Những Người Đó","tomTat":"Vương Lâm dùng tinh điểm Cổ Thần và đầu lâu Đạo cổ phát khí tức Đạo cổ, ánh mắt dung hợp với đầu lâu xuyên thấu nguyên thần Huyết Thần Tử, xé đôi nguyên thần, tan thân xác, giết chết Huyết Thần Tử — giải quyết hai nhân quả: bị đuổi giết năm xưa và lời hứa trong mộng với nữ tử Diêu gia tám trăm năm trước. Cổ Yêu lục tinh vốn nương nhờ Huyết Thần Tử chữa thương từ lâu hiện nguyên hình trăm trượng từ yêu khí thi thể, liều mạng phản kích bằng đủ loại thần thông và vương tộc pháp khí yêu đao Táng Thổ. Vương Lâm một quyền phá nát tất cả, một chưởng đoạt yêu đao, lực hút kéo Cổ Yêu thu nhỏ bắt sống. Cổ Yêu cầu xin tha mạng, tiết lộ bí mật kinh thiên liên quan Diêu gia — nơi có thể đạt thần thông ba mạng. Vương Lâm chất vấn Lỗ Phu Tử ngăn cản kết thúc nhân quả chính vì bí mật này, Lỗ Phu Tử thừa nhận rồi cáo từ tiếp tục chuẩn bị chiến tranh, giữ ngạo cốt dù rung động. Chu Cẩn đứng phía sau, ánh mắt phức tạp trước sức mạnh Vương Lâm, tự cảm thấy mình như con kiến trước khí Đạo cổ."},{"chuong":1407,"tieuDe":"Vương Tộc Yêu Đao","tomTat":"Vương Lâm ôm quyền hứa hẹn báo đáp Lỗ Phu Tử khi chiến tranh giới ngoại xảy ra, thái độ khách khí khiến Lỗ Phu Tử thừa nhận chịu thua và hòa giải. Linh Động Thượng Nhân tự giới thiệu là lão tổ Linh Động tộc (một vạn tộc nhân), Chu Cẩn tự xưng lão tổ Phụng Thiên Lang tộc (đại tộc thái cổ) — Lỗ Phu Tử kinh ngạc trước ấn ký nô phó trên mi tâm cả hai. Lỗ Phu Tử tiết lộ Yêu Tông và Thần Tông ở Vân Hải tinh vực truyền lệnh phong bằng di chiếu chủ nhân phong giới, thông báo tứ đại tinh vực chuẩn bị chiến tranh với Thái Cổ Tinh Thần. Ông tự bộc lộ từng là tiên quân nhỏ của Lôi Tiên Giới, tận mắt thấy trận chiến bi thảm, mang thù sâu với giới ngoại. Lỗ Phu Tử long trọng nghênh tiếp Vương Lâm bằng kim quang vạn trượng, chín kim long, hư ảnh tiên nhân, mời uống rượu tiên hóa giải hiềm khích. Vương Lâm kể lại chuyện diệt Thiểm Lôi tộc, gặp Tán Linh Thượng Nhân, bị Trường Tôn hội đuổi giết, nhưng giữ lại chi tiết về vùng đất Điên Lạc. Cuối chương Vương Lâm nhắc đã gặp lão tổ Chiến gia Chiến Tinh Dã ở giới ngoại, Liệt Vân Tử chấn động kích động xá sâu hỏi lão tổ hiện ở đâu."},{"chuong":1408,"tieuDe":"Một Chém Hết Ân Oán","tomTat":"Vương Lâm thông báo cho Liệt Vân Tử rằng lão tổ Chiến Tinh Dã đã chết trong Thất Thải Giới tại Vân Hải, bị Chưởng Tôn của giới ngoại Thái Cổ Tinh Thần giết. Liệt Vân Tử tâm thần trọng thương, quyết truyền thừa quyết tâm báo thù cho đời sau Chiến gia. Vương Lâm giải thích Thất Thải Giới hấp thụ đạo niệm tu sĩ giới nội, là mối họa khủng khiếp trong đại chiến. Viêm Lôi Tử tiết lộ bản thân từng là trưởng lão Tu Chân Liên Minh, xác nhận tổng bộ cũng có Thất Thải Giới. Lỗ Phu Tử nhận đi Yêu Tông ở Vân Hải báo tin liên lạc các lực lượng giới nội tìm diệt sáu Thất Thải Giới còn lại; Vương Lâm nhận phá hủy cái ở Tu Chân Liên Minh, đồng ý cho Viêm Lôi Tử đi cùng. Vương Lâm thu Chu Cẩn và Linh Động vào Thiên Hoàng Lô, rồi lên đường thực hiện việc cuối cùng ở La Thiên: bắt một con thú mạnh ngang bước thứ ba để luyện cổ thần bổn mệnh thú. Trên đường đi, hắn tình cờ ngang qua Nhiễm Vân Tinh, hồi tưởng tình cha con trăm năm với Vương Bình và Liễu Mi trên Thiên Huyễn Tinh, rồi hạ xuống Nhiễm Vân Tinh trong cảnh mùa thu u ám."},{"chuong":1409,"tieuDe":"Tai Hoạ Ngầm Của Thất Thải Giới","tomTat":"Trên Nhiễm Vân Tinh, lão phu nhân Tôn Linh — lão tổ tông duy nhất tu đạo của Tôn gia — biết đại hạn đến gần, không sống quá bảy ngày. Bà triệu tập con cháu dặn dò di huấn: đời sau tuyệt đối không tu đạo, ở phàm trần hưởng phú quý, phóng uy áp buộc mọi người tuân mệnh. Sau khi con cháu lui, bà ngồi nhìn trăng hồi tưởng cố nhân. Vương Lâm dùng thân phận Hứa Mộc xuất hiện, đi tới như phàm nhân, tái ngộ Tôn Linh và trò chuyện suốt đêm. Sáng hôm sau, Tôn Linh bình thản chấp nhận cái chết, Vương Lâm để lại một viên đan dược phòng nếu đổi ý rồi thở dài từ biệt. Vương Lâm sau đó đi qua đỉnh núi, sông, biển, bình nguyên, rừng sâu — từng nơi in dấu chân Vương Bình — tưởng niệm con trai đã mất, cảm nhận hồn phách Vương Bình trong Thiên Nghịch Châu. Cho dù là thất tinh Cổ Thần danh chấn giới ngoại, hắn vẫn chỉ là một người cha. Mang thân ảnh cô độc tóc bạc rời khỏi Nhiễm Vân Tinh, chỉ còn tiếng thở dài vang vọng."},{"chuong":1410,"tieuDe":"Tuổi Già Thoái Chí","tomTat":"Vương Lâm xông vào cấm địa sương mù ở rìa La Thiên Tinh Vực để thực hiện việc cuối cùng tại đây: săn con U Minh Thú khổng lồ hình kình ngư nhằm biến nó thành Cổ Thần bổn mệnh thú. Hắn dùng tàn tích tu chân tinh do con thú bài tiết ra làm dẫn đường, lần theo khí tức tìm tới nơi nó đang ngủ say, rồi tiếp cận ở tốc độ tối đa thất tinh Cổ Thần đánh một chưởng khí tức Đạo cổ hoàn thành phong ấn bên ngoài. Giao chiến nổ ra dữ dội, Vương Lâm hóa thân ngàn trượng dùng sức mạnh thuần túy đẩy lùi và ném con thú, nhưng U Minh Thú lộ bản chất thú linh giảo hoạt, giả vờ bỏ chạy rồi quay lại thi triển thần thông thôn phệ — miệng mở rộng tới hơn mười vạn trượng, hồn phách hiện ra kích cỡ bằng cả tinh vực, nuốt hàng chục tu chân tinh hoang dã. Vương Lâm dồn toàn lực đấm một quyền kết hợp Linh Động, Chu Cẩn, đầu Đạo cổ, lôi đình và hỏa diễm chín màu với uy lực tiếp cận Không Linh, rồi lần lượt hy sinh Cổ Tức Diệp và Vọng Nguyệt chắn hố đen để mua thời gian, thắp sáng đủ bảy tinh điểm hoàn thành phong ấn hồn phách. Tuy nhiên ngay khi phong ấn vừa xong, ánh sáng thất thải bùng lên dữ dội từ hồn khẩu U Minh Thú, phá hủy hơn nửa phong ấn ngoài và dập tắt ba tinh điểm — hóa ra con thú từng nuốt một phần Thất Thải Giới vào thế giới bên trong cơ thể. Vô số thân ảnh Minh Chí Giả tràn ra nói về phong thiên đạo, và từ hồn khẩu xuất hiện một tấm bia đá khổng lồ khắc chữ đỏ như máu: Đạo Kinh."},{"chuong":1411,"tieuDe":"Săn U Minh Thú","tomTat":"Bia đá Đạo Kinh trên hồn U Minh Thú bùng phát, thao túng Minh Chí Giả thành lốc xoáy tấn công Vương Lâm khiến hắn lùi ba bước, đồng thời dập tắt thêm hai tinh điểm trên hồn thú. U Minh Thú sợ hãi thi triển thần thông tàng hình biến mất khỏi tinh không cùng mọi thứ. Vương Lâm nổi giận điên cuồng vì Linh Động, Chu Cẩn, Vọng Nguyệt, cổ Tức Diệp đều nằm trong cơ thể thú, bùng phát bổn nguyên lôi đình khuếch trương lôi đồ lên tám ngàn vạn trượng, dung hợp Thiên Hoàng Lô biến tinh không thành lôi trì. Hắn thi triển Chu Tước hư ảnh dung hợp lửa chín màu, đánh ra hơn mười vạn cấm chế khai mở Phần Giới Cổ Tán xả lửa diệt thế, luyện hóa tinh không co rút xuống sáu trăm vạn trượng, để lộ Phong Giới Đại Trận bên dưới. Cuối cùng Vương Lâm dùng chín giọt độc dịch từ Thiên Hoàng Lô tạo sương độc bức U Minh Thú hiện nguyên hình, xông tới vỗ tay lên phong ấn chỉ còn một tia trên đầu thú."},{"chuong":1412,"tieuDe":"Luyện!","tomTat":"Vương Lâm hoàn thành ba bước phong ấn U Minh Thú: phong ấn bên ngoài bằng chưởng lực truyền sức sống, hồn phong bằng Côn Cực Tiên quất 100 roi ép hồn thoát ra rồi đưa bảy tinh điểm Cổ Thần xuyên vào hồn khẩu khôi phục thất tinh phong ấn, và phong ấn máu thịt bằng cách xé miệng U Minh Thú đánh cấm chế Cổ Thần lực vào toàn bộ nội tạng mạch máu khớp xương. Tuyên phong bằng thân phận vương tộc thất tinh Cổ Thần, U Minh Thú cúi đầu thần phục. Đầu Côn Cực Tiên vỡ tan sau roi thứ 100, tuôn kim quang vạn trượng. Sau khi thiết lập liên hệ máu thịt, sức sống vô biên từ U Minh Thú tràn vào khiến thân Cổ Thần bành trướng tới sáu ngàn trượng; thu nhỏ lại ngoại hình trẻ hơn hẳn, mang màn hư ảo — ngoài tu sĩ bước ba ai cũng thấy hắn như hồn phách. Vương Lâm đọc toàn bộ ký ức U Minh Thú — ký ức hỗn loạn, rõ nhất chỉ là cảnh Thất Thải Giới mấy trăm năm trước. Ra lệnh nhả Linh Động Thượng Nhân, Chu Cẩn, Cổ Tức Diệp, Vọng Nguyệt. Phát hiện U Minh Thú khi nuốt Thất Thải Giới đã phá vỡ vách ngăn hấp thụ một Đạo Quả màu cam mười trượng mang đạo niệm hỗn tạp, thu lấy Đạo Quả, nhận định nó có thể giúp ba đạo bổn nguyên nhân quả sinh tử chân giả viên mãn. Sau khi mất Đạo Quả, U Minh Thú trở lại ngơ ngác nhưng thông minh hơn trước nhờ đã hấp thụ một phần."},{"chuong":1413,"tieuDe":"Bổn Mệnh Thú","tomTat":"Vương Lâm bấm quyết thu phục U Minh Thú, hóa u quang dung hợp vào tinh điểm thứ hai trên mi tâm, hoàn tất bổn mệnh thú thứ hai. Bên trong thế giới thần thông U Minh Thú, một tu sĩ tự xưng lão đạo vẫn mắc kẹt suốt mấy trăm năm kể từ khi Thất Thải Giới sụp đổ, kiên trì tìm đường ra. Vương Lâm tới huyết tinh đỏ như máu trong La Thiên Tinh Vực, lôi Cổ Yêu ra uy hiếp, buộc khai bí mật về khe không gian chứa tế đàn Phong Diệt Tộc và Tam Mệnh Thuật. Cổ Yêu dẫn đường, định giăng bẫy nhưng bị Vương Lâm nhìn thấu khi tiết lộ biết về tế đàn mất tích ở Thái Cổ Tinh Thần, buộc Cổ Yêu không dám đánh cuộc, tự giao nộp tòa huyết các. Vương Lâm phong ấn Cổ Yêu, nay sở hữu hai trong ba tòa huyết các tế đàn Phong Diệt Tộc, rồi di chuyển tới ranh giới La Thiên – Vân Hải, tuyên bố sẽ thanh toán mối thù với Thủy Đạo Tử. Tại giới ngoại Thái Cổ Tinh Thần, Chưởng Tôn truyền mệnh lệnh triển khai trận chiến thứ ba giữa Phong Giới và các bộ tộc Thái Cổ, ra lệnh tàn sát Phong Giới và xóa bỏ giới nội."},{"chuong":1414,"tieuDe":"Tế Đàn Của Phong Diệt Tộc","tomTat":"Thủy Đạo Tử ngồi đả tọa trên tu chân tinh Thần Tông, cảm nhận khí tức Vương Lâm trở về cùng Linh Động Thượng Nhân và Chu Cẩn, vô cùng khiếp sợ. Hắn phát bảy đạo mệnh lệnh: triệu tập tu sĩ Vân Hải tinh vực bố trí Cửu Diệt Lê Thiên Trận, bắt toàn bộ người Quy Nguyên Tông về Thần Tông chờ lệnh chém sạch, ép Mộc Băng Mi nuốt đan dược ra bế quan trợ giúp, triệu tông chủ Phá Thiên Tông đến đe dọa diệt môn, sai vua mãnh thú Thái A La bị phong ấn giết người đổi tự do. Hắn tự xưng đồng tử chủ nhân phong giới, vu cáo Vương Lâm là gian tế Thái Cổ Tinh Thần chiếm Thiên Nghịch, kêu gọi bốn đại tinh vực truy sát. Hắn dùng mảnh mai rùa liên lạc viễn cổ tiên vực, nhận chiếc chuông vàng vốn dùng dung hợp Phong Giới Đại Trận ngăn xâm lấn một trăm năm, nhưng không có ý thực hiện mà định dùng riêng để tự bảo mệnh và lập công với chưởng tôn. Hai đại năng ẩn cư tại Triệu Hà — Chu Đức đổi lục phẩm đạo linh, Vân Phong Tử đổi Định Thần Thuật — đều nhận lời ra tay một lần trợ giúp Thủy Đạo Tử."},{"chuong":1415,"tieuDe":"Hèn Hạ","tomTat":"Sáu ngọc giản Thủy Đạo Tử phát ra khắp tứ đại tinh vực, vu Vương Lâm là gian tế giới ngoại, đả động quân tâm ngay thời điểm chuẩn bị đại chiến. Tại Quỷ Tông cấp mười hai, lão Đại Hư nhận tin có kẻ muốn dùng năm triệu âm dương môn đồ đổi yêu thánh ra tay. Ở Triệu Hà tinh vực, nữ tử hư ảo nhận ra Vương Lâm là quân cờ chưởng tôn, nam tử thanh y nhận ra hắn là tiểu tử năm đó. Trong Vũ tiên giới, Thanh Lâm dùng thần lực ngưng tụ nước mưa cả Vũ giới thành lệnh bài truyền thần niệm bảo vệ Vương Lâm, quát Tư Đồ Nam ngồi xuống và tiết lộ Thủy Đạo Tử là nô bộc sư tổ Tư Đồ Nam. Nam tử áo đỏ ở sơn cốc cùng Lỗ Phu Tử tỏ ý tán thưởng Vương Lâm, quyết xem tầm mắt chủ nhân phong giới. Phân tông Thần Tông khống chế toàn bộ Quy Nguyên Tông, Lữ Yên Phi trầm mặc chấp nhận. Mộc Băng Mi lấy ra viên đan Thủy Đạo Tử tặng, do dự. Hơn vạn tu sĩ triển khai Cửu Diệt Lê Thiên Trận tại Thần Tông. Vương Lâm trên đường tới Thần Tông, sát niệm manh nha sát lục bổn nguyên, sát khí đóng băng mười vạn trượng, xuất hiện trước Thần Tông tuyên bố thay chủ nhân phong giới giết Thủy Đạo Tử, vang danh giới nội."},{"chuong":1416,"tieuDe":"Một Trận Chiến Này","tomTat":"Vương Lâm đứng trước Thần Tông hô to kết tội Thủy Đạo Tử cấu kết giới ngoại, bán chủ cầu vinh, tuyên bố thay mặt chủ nhân phong giới diệt kẻ phản bội, tiếng nói truyền tới toàn bộ tu sĩ đại thần thông tứ đại tinh vực. Sát khí từ sương mù và thân thể Vương Lâm dung hợp thành sát lục bổn nguyên, thứ mà chủ nhân phong giới năm xưa cũng không nghiên cứu ra, khiến mọi tu sĩ bước thứ ba chấn động. Gần vạn tu sĩ Vân Hải bị uy áp bức lui tới chân Thần Tông, bùng phát ý chí vinh quang quyết tử bảo vệ thánh địa, dùng huyết nhục điều khiển Cửu Diệt Lê Thiên Trận chưa hoàn chỉnh xông lên; thực chất Thủy Đạo Tử âm mưu cho họ chết để kích động phẫn nộ giới nội nhưng kế hoạch phản tác dụng. Vương Lâm không nỡ giết, thi triển Định Thân thuật ở cực hạn; trước ý chí vinh quang Vân Hải, thuật thăng hoa thành Định Thần thuật — định cả thần niệm, ý chí, chuyển động thiên địa — rồi vung tay áo dời toàn bộ tu sĩ mà không tổn thương. Vương Lâm tiến lên tu chân tinh Thần Tông thách đấu, Thủy Đạo Tử triệu hình ảnh hư ảo đám người Quy Nguyên Tông bị vây dưới ngọn núi khổng lồ để uy hiếp đạo tâm Vương Lâm, nhưng Vương Lâm bình thản đáp lại như đã tiên liệu hết, khiến Thủy Đạo Tử sửng sốt, đúng lúc đó biến cố bất ngờ xảy ra."},{"chuong":1417,"tieuDe":"Vinh Quang Của Vân Hải","tomTat":"Trong thiên địa hư ảo, Thủy Đạo Tử dùng ngọn núi pháp bảo Thần Tông đè tu sĩ Quy Nguyên Tông nhưng bị huyết kiếm Vương Lâm đâm xuyên phá nát, đồng thời giết sạch hơn mười tu sĩ áo đen trong ba nhịp thở. Vương Lâm vỗ một chưởng hiện bàn tay che trời, Thủy Đạo Tử tung Thất Thải Đinh chống cự — hai bên đều bị thương, Thủy Đạo Tử phun máu kêu cứu Chu Đức. Lão già áo đen Chu Đức (cao thủ bước thứ ba, phân thân) và nam tử trung niên dùng hạt châu bàn tính cùng giáp công Vương Lâm. Vương Lâm bình tĩnh triệu hồi Linh Động Thượng Nhân qua tinh điểm Cổ Thần đánh bại phân thân Chu Đức, Chu Cẩn thi triển Quần Lang Bái Nguyệt phá vỡ hạt châu bàn tính lộ bản thể nam tử trung niên rồi truy kích. Thủy Đạo Tử liều mạng triệu hồi vô số Âm Dương Môn Đồ hóa thành trường thương dung hợp toàn bộ tu vi và hương hỏa cả đời đâm Vương Lâm, uy lực kinh thiên khiến tu chân tinh nứt vỡ dường như sắp hủy diệt."},{"chuong":1418,"tieuDe":"Yếu Yếu Yếu!","tomTat":"Vương Lâm nhân danh Chủ nhân phong giới tung hai quyền liên tiếp đánh bại hoàn toàn Thủy Đạo Tử — quyền thứ nhất phá tan cây thương hương hỏa, đánh hắn bắn vào núi vỡ; quyền thứ hai có đầu Đạo cổ dung nhập, phá hủy Âm Dương Tiên Long cùng mọi phòng ngự, nổ tung ngực hắn. Chu Đức hoảng sợ trách Thủy Đạo Tử hại mình, Vân Phong Tử quyết định bỏ vụ mua bán Định Thần Thuật. Tu sĩ hóa hình Thái A La xuất hiện bái kiến Vương Lâm, đề nghị giải phong ấn đổi lấy dẫn bộ tộc trong khe Vân Hải đánh giới ngoại, Vương Lâm chưa đáp. Thủy Đạo Tử trong tuyệt vọng phun ra cái chuông nhỏ chứa tiên khí Viễn Cổ Tiên Vực, chuông va vào quyền Vương Lâm bộc phát đạo khí vàng khuếch tán khắp tứ đại tinh vực, quét sạch sương mù, khiến Phong Giới Đại Trận lần đầu tiên hiện hình trước mắt gần như toàn bộ tu sĩ giới nội. Hồng Sam Tử ở Vân Hải nhận ra khí tức Viễn Cổ Tiên Vực, phá không lao tới Thần Tông. Lão già hư ảo từ Thi Âm Tông nhận ra chuông là vật dung hợp Phong Giới Đại Trận, cũng phá không lao tới Thần Tông."},{"chuong":1419,"tieuDe":"Chiếc Chuông Vàng","tomTat":"Thủy Đạo Tử phun máu tươi lên chiếc chuông vàng Viễn cổ Tiên Vực kích nổ toàn bộ sức mạnh bên trong, tạo cuồng phong màu vàng đủ sức hủy diệt toàn bộ Vân Hải Tinh Vực. Kế hoạch của hắn là chôn vùi Vương Lâm cùng toàn bộ Vân Hải, tạo sơ hở Phong Giới Đại Trận rồi trốn vào Thái Cổ Tinh Thần. Hồng Sam Tử, Nam Vân Tử (lão già Thi Âm Tông), Chu Đức, Vân Phong Tử, Linh Động Thượng Nhân, Chu Cẩn, hơn mười tu sĩ Yêu Tông cảnh Thiên Khán Suy Kiếp, trưởng lão Thần Tông, Thái A La và Đại Hư Thượng Nhân (Quỷ Tông) đồng loạt ra tay chống cuồng phong nhưng hoàn toàn bất lực. Vân Hải chấn động dữ dội, vô số phàm nhân tử vong, Phong Giới Đại Trận lóe hào quang bất ổn. Hồng Sam Tử cười thảm tuyên bố Vân Hải không cứu nổi, ra lệnh lui rồi xông thẳng tới giết Thủy Đạo Tử. Vương Lâm trầm mặc trước cảnh báo thù cá nhân liên lụy sinh linh, sau đó kích hoạt tinh điểm thứ hai trên mi tâm triệu hồi Vu Minh Thú khổng lồ. Vu Minh Thú mở Vu Minh Hồn Khẩu nuốt trọn cuồng phong, cứu Vân Hải khỏi hủy diệt, khiến Thủy Đạo Tử hoảng sợ và mọi người ngây ra kinh ngạc."},{"chuong":1420,"tieuDe":"Cơn Lốc Màu Vàng","tomTat":"U Minh thú sau khi nuốt cơn lốc màu vàng bị tu sĩ bốn phía nhìn chằm chằm, hoảng sợ vọt về nép vào Vương Lâm như hài tử nép cha mẹ. Chu Đức, Vân Phong Tử cùng tu sĩ các tông đều nổi tham niệm muốn thu phục con thú, nhưng khi thấy lực va chạm khi nó cọ đầu vào Vương Lâm ngang tu sĩ bước thứ ba, tất cả dập tắt ý định. Hồng Hủ Tử nhận định U Minh thú là bổn mạng thú, đánh giá sự lựa chọn của chủ nhân phong giới không sai, trao đổi ánh mắt với tu sĩ Liên Minh Tinh Vực và Thi Âm Tông. Thủy Đạo Tử lợi dụng lúc mọi người chú ý thú để lén lùi trốn nhưng bị Vương Lâm phát hiện truy kích. Vương Lâm ra một quyền hư ảo phá hủy dòng xoáy hàn nhiệt tím sẫm, đánh nát song chưởng và toàn thân Thủy Đạo Tử. Nguyên thần Thủy Đạo Tử thoát ra bỏ chạy, bất chấp mặt mũi van xin tha mạng, tự xưng trưởng lão Thần Tông, tự nguyện làm nô bộc Vương Lâm, còn tuyên bố biết tin tức giới ngoại."},{"chuong":1421,"tieuDe":"Phong Tôn!","tomTat":"Vương Lâm lao tới đánh liên tiếp sáu quyền vào nguyên thần Thủy Đạo Tử, mỗi quyền gắn một lý do: vì chủ nhân phong giới, vì Lý Thiến Mai, vì tu sĩ Vân Hải và Quy Nguyên Tông, vì cơn lốc màu vàng, vì chính mình. Thủy Đạo Tử trước khi chết lật quân bài cuối: tiết lộ tính mạng tương liên Mộc Băng Mi qua liên kết mệnh hồn bằng đan dược và khôi phục tu vi, buộc Vương Lâm dừng tay. Mộc Băng Mi xuất hiện trong thiên địa biến ảo, trải lòng thừa nhận mình chính là Liễu Mi, kể nỗi đau Côn Hư bị hủy, tự nhận nợ Bình Nhi, nhờ nói Lý Mộ Uyển mới là mẫu thân, rồi muốn lấy cái chết giải gút mắc hai ngàn năm. Vương Lâm dùng Định Thân Thuật chế trụ nàng, đánh quyền cuối bóp nát hồn phách Thủy Đạo Tử, rồi thi triển Đạo Cổ Hóa Mệnh Thuật chuyển sinh cơ sang Mộc Băng Mi cứu sống nàng. Thủy Đạo Tử — nô bộc chủ nhân phong giới, đại trưởng lão Thần Tông, tu sĩ bước thứ ba — xác nhận chết. Sau đó tu sĩ Yêu Tông, Thần Tông, Quỷ Tông cùng đông đảo tu sĩ Vân Hải đồng loạt tham kiến Vương Lâm với danh hiệu Phong Tôn."},{"chuong":1422,"tieuDe":"Phong Tôn!","tomTat":"Vương Lâm trở về Thần Tông, được toàn bộ tu sĩ giới nội tham kiến với danh xưng Phong Tôn — chủ nhân phong giới đời này. Chu Đức và Vân Phong Tử từ Triệu Hà tinh vực vái chào, Hồng Sam Tử công nhận và cảnh báo chuẩn bị chết trận chống giới ngoại. Nam Vân Tử từ Thi Âm Tông nêu vấn đề U Minh thú nuốt lốc vàng, chuông vàng bị hủy, cần phá Thất Thải Giới còn lại. Vương Lâm phong Mộc Băng Mi làm tông chủ Thần Tông, lệnh Quy Nguyên Tông dung nhập, rồi mang U Minh thú, Linh Động Thượng Nhân, Chu Cẩn rời đi hướng về Côn Hư tinh vực cứu Thanh Thủy. Phía giới ngoại, Trưởng Tôn hội phát chiếu lệnh tổng tấn công, hơn mười bộ tộc Thái cổ Tinh Thần đồng loạt ra quân, gần chín vạn tu sĩ tập hợp phía đông Phong Giới Đại Trận. Đông Địch Tử, Nam Chiếu Thượng Nhân, lão tổ Hỏa Tước tộc và Vân Lạc đại ti họp bàn chiến lược, Vân Lạc tiết lộ mục đích thật sự là bố trí truyền tống trận và giết nhanh Vương Lâm."},{"chuong":1423,"tieuDe":"Một Trận Chiến Nhập Giới","tomTat":"Đông Địch Tử bề ngoài tươi cười nhưng trong lòng coi thường Vương Lâm, coi hắn chỉ là Thiên Nhân suy kiếp, xác định mục đích trận chiến là giết người cướp vật và thuận tay giết Vương Lâm. Thiên Phạt Điện — một trong tứ điện của Trưởng Tôn hội — xuất hiện dưới hình thức tòa lầu các đen khổng lồ cùng mấy ngàn tu sĩ Thị Kiếm tộc bên ngoài Phong Giới Đại Trận, lão nhân bên trong tuyên bố đốc chiến và phát động chiến tranh. Bên trong Thái Cổ Tinh Thần, nhiều cường giả đồng loạt ra tay: nữ tử ung dung cao quý dùng ngọc như ý tạo cơn lốc chín cánh hoa và ném thoa vàng xuyên không tới Lam Sơn thúc giục Lam Mộng Đạo Tôn. Lam Mộng Đạo Tôn trải qua thống khổ phân vân rồi quyết định hy sinh tu vi cả đời, phun máu tươi dung nhập dây đàn đứt phóng lên tinh không. Đồng tử tam đồng chi tu phá băng phóng ba đạo u quang, nữ tử hồng y tóc đỏ cắn ngón tay hóa ba quỷ ảnh. Tất cả sức mạnh hội tụ bên ngoài Phong Giới Đại Trận, đồng thời Chưởng Tôn dù bị thương vẫn thi triển Tĩnh Trung Lao Nguyệt lôi trận hồn từ bên trong, khiến đại trận chấn động dữ dội. Vương Lâm đang tiến bước trong giới nội cảm nhận chấn động, ngẩng đầu nhìn — hắn đứng ngay trước mặt chín vạn tu sĩ bên ngoài mà chỉ bị trận pháp ngăn cách."},{"chuong":1424,"tieuDe":"Phá Trận","tomTat":"Thái Cổ Tinh Thần phát động trận chiến đầu tiên, nhắm vào Vân Hải tinh vực — đúng nơi Vương Lâm đang đứng. Vương Lâm hoàn toàn có thể rời đi nhưng chọn ở lại tử chiến, lĩnh ngộ sát lục bổn nguyên chân chính: sát lục vì đại nghĩa, vì bảo vệ người và vật mình muốn giữ gìn, khiến sát lục bổn nguyên điên cuồng tăng trưởng. Hắn triển khai toàn bộ chiến lực — kiếm khí, Huyết kiếm, triệu Linh Động Thượng Nhân và Chu Cẩn, Lôi đồ, lửa chín màu — đứng như chiến tiên nghênh đón đại quân. Từ giới ngoại, sáu cường giả gồm Chưởng Tôn, hai tiên phi, ba tu sĩ bước thứ ba phối hợp phá Phong Giới Đại Trận: một người bí ẩn rút trận hồn, năm pháp bảo đối kháng trận linh phản kích dữ dội. Trận linh ngưng tụ trường thương sấm sét, roi tử ý, lưu tinh chùy, chiến xa lửa, Lang nha bổng chống trả quyết liệt. Cuối cùng năm người đồng loạt hạ lệnh cho pháp bảo nổ tung, xé rộng khe hở trên Phong Giới Đại Trận. Chiến tranh giới nội — giới ngoại chính thức bắt đầu."},{"chuong":1425,"tieuDe":"Không Thể Lui","tomTat":"Phong Giới Đại Trận bị xé rách, chín vạn tu sĩ giới ngoại do Đông Địch Tử, Nam Chiếu Thượng Nhân, lão tổ Hỏa Tước Tộc dẫn đầu điên cuồng tràn vào giới nội. Ngọc bội mang khí tức chủ nhân Phong Giới tự hiện ra trên trận pháp, kích hoạt Khai Thiên Phủ chém hai lần giết gần mười nghìn kẻ địch, đồng thời phong tỏa lão già gầy nhom từ lầu các đen. Vương Lâm một mình nghênh chiến mấy vạn tu sĩ, dùng kiếm khí, hư hỏa, lôi đồ, huyết kiếm, thân thể Cổ Thần giết hàng ngàn người, Quang Ảnh Thuẫn vỡ nhưng vết thương lập tức khép lại. Linh Động Thượng Nhân và Chu Cẩn theo thần niệm Vương Lâm ngăn cản Đông Địch Tử, nhưng hắn một mình đấu hai người mà không hạ phong. Vân Lạc Đại Ti tiến vào trận, sợ hãi ra lệnh giết Vương Lâm. Nam Chiếu Thượng Nhân (cảnh Không Linh, có độc công cùng tề danh Đại Hoang Thượng Nhân) cùng lão tổ Hỏa Tước Tộc liên thủ tấn công, buộc Vương Lâm phải lui. Viện quân từ hai phía đổ tới: hơn mười bộ lạc Thái cổ Tinh Thần nhận lệnh Chưởng Tôn qua truyền tống trận tăng viện giới ngoại, trong khi Hồng Sam Tử và Vân Phong Tử bất ngờ xuất hiện từ tinh không Vân Hải dẫn mấy vạn tu sĩ tiếp viện giới nội."},{"chuong":1426,"tieuDe":"Phản Kích","tomTat":"Mấy vạn tu sĩ Vân Hải từ xa bay tới như mưa cầu vồng trong tinh không, hô vang Vân Hải muôn năm, chính thức tham chiến bảo vệ Vân Hải. Hồng Sam Tử mặc áo đỏ cười dài lao ra chiến đấu cùng Nam Vân Tử, lộ khí thế bước thứ ba. Nguy cơ lớn nhất của Vương Lâm là Nam Chiếu Thượng Nhân — tu vi Không Linh, ra một chưởng chứa linh lực hút Vương Lâm vào hương hỏa giới riêng, nơi bầu trời và mặt đất đen kịt với hàng trăm triệu dân hương hỏa, bàn tay khổng lồ do không trung hóa thành giáng xuống. Trong lúc nguy cấp Vương Lâm triệu hộ tí Cổ Thần trên cánh tay phải đỡ đòn, Cổ Thần tung quyền đánh văng bàn tay vạn trượng rồi tan đi, hộ tí thêm vết nứt. Tiếp đó Vương Lâm dung nhập Đạo cổ cùng hư hỏa vào quyền đấm phá tan bàn tay đen thoát khỏi hương hỏa giới. Cả hai bên đều bị thương — Vương Lâm phun máu lui về phía sau, Nam Chiếu Thượng Nhân tay phải chảy máu không thể truy kích. Nam Chiếu Thượng Nhân khiếp sợ trước sức mạnh thân thể Vương Lâm, nhận định nếu hắn đạt bước thứ ba sẽ cực kỳ kinh khủng, quyết tâm tuyệt đối không để sống sót."},{"chuong":1427,"tieuDe":"Linh Thần","tomTat":"Vương Lâm bị thương nặng sau khi đối đầu tu sĩ Không Linh, lần đầu cảm nhận sự kinh khủng của cảnh giới này, lui lại giết hàng loạt tu sĩ giới ngoại hút sinh cơ hồi phục. Hồng Sam Tử thi triển thần thông bản mệnh Huyết Sam, bức máu huyết hàng ngàn tu sĩ giới ngoại thành trường sam đỏ biến họ thành xác sống chém giết đồng đội, Nam Chiếu Thượng Nhân nhận ra hắn là Huyết Sam đồng tử trong truyền thuyết kinh hoàng từ lần đại chiến trước. Nam Chiếu Thượng Nhân bị huyết sam phá hủy thân thể, dùng thân dự phòng khôi phục, cùng Đông Địch Tử, lão tổ Hỏa Tước Tộc và hai tu sĩ bước thứ ba khác — tổng năm người vây đánh Hồng Sam Tử. Nam Vân Tử bỏ qua chiến trường lao tới Phong Giới Đại Trận tu bổ, tuyên bố giới nội chưa chuẩn bị xong, mượn Linh Động Thượng Nhân và Chu Cẩn làm hộ pháp. Vân Lạc đại ti nhận định tổn thất gần hai vạn tu sĩ giới ngoại, ra lệnh Thị Kiếm Tộc dùng Phá hồn nhất kiếm chặn Khai Thiên Phủ, đồng thời lệnh Tam lão Phong Diệt Tộc truy sát Vương Lâm. Đại quân Vân Hải tinh vực lao vào loạn chiến, nhiều tu sĩ hy sinh bi tráng, mười rồi trăm rồi ba trăm người tự bạo liên tiếp mới tiêu diệt được một tu sĩ giới ngoại thiên nhân đệ tam suy."},{"chuong":1428,"tieuDe":"Thử Sam, Phi Sam!","tomTat":"Chương mở đầu bằng lời kể flash-forward của một tu sĩ từng tham chiến ở Vân Hải, nay đã thành Thiên Nhân Đệ Nhất Suy, đăng đàn giảng đạo về vinh quang gắn liền với Vương Lâm. Tại chiến trường, Vương Lâm đơn thương độc mã nhảy vào giữa đại quân giới ngoại, dùng hỏa diễm, lôi đình, huyết kiếm chém giết điên cuồng. Ba tử sĩ Phong Diệt Tộc ẩn trong đại quân hiện thân hiến tế sinh mạng, thi triển thần thông bộ tộc đánh ba đạo phong ấn bất khả cự lên Vương Lâm: phong ấn nguyên lực, phong ấn thể lực khiến lão hóa, phong ấn sinh cơ rút sức mạnh Cổ Thần. Vương Lâm kịp tung quyền giết cả ba nhưng phong ấn không tan, mất toàn bộ sức chiến đấu. Vân Lạc Đại Tỉ ra lệnh cho mấy vạn tu sĩ giới ngoại dồn toàn lực oanh tạc, Vương Lâm nhiều lần phun máu trọng thương nhưng thân thể Cổ Thần vẫn trụ vững. Hình ảnh hắn một mình chịu đòn khiến toàn bộ tu sĩ Vân Hải chấn động muốn liều chết bảo vệ. Vương Lâm cố ý chịu cuồng phong tổng lực, mượn chính ngoại lực tấn công phá lần lượt ba đạo phong ấn, khôi phục toàn bộ nguyên lực, dung nhan và sức mạnh Cổ Thần, hét lên thách thức giữa cuồng phong."},{"chuong":1429,"tieuDe":"Ba Đạo Phong Ấn!","tomTat":"Vương Lâm bước ra khỏi cuồng phong do vạn tu sĩ giới ngoại tấn công, thân thể hùng mạnh khiến địch chấn động lui lại, tu sĩ Vân Hải hô vang Phong Tôn vinh quang. Tuy nhiên thương thế Vương Lâm rất nặng, tốc độ khôi phục thất tinh Cổ Thần không theo kịp cường độ trận chiến. Gần ba vạn tu sĩ Vân Hải cố bày trận pháp cải tiến nhưng liên tục thất bại do Vân Lạc Đại Ti chỉ huy đại quân giới ngoại phá hoại. Hồng Sam Tử bỏ đối thủ phá không gian lao tới Vân Lạc Đại Ti nhưng rơi vào bẫy: tảng băng khổng lồ chứa đồng tử hàn băng phá tan Phong Giới Đại Trận tiến vào giới nội, nổ tung thành cuồng phong hàn băng quét chết gần một vạn tu sĩ Vân Hải. Nữ tử áo đỏ Tiên Phi ẩn trong cuồng phong dùng tam đầu quỷ ảnh đánh trúng đòn chí mạng Hồng Sam Tử. Nàng tuyên bố mọi chuyện nằm trong kế hoạch của Vân Lạc Đại Ti, phá sĩ khí Vân Hải rồi lao tới tấn công Nam Vân Tử, buộc Nam Vân Tử bỏ sửa chữa Phong Giới Đại Trận cùng Linh Động và Chu Cẩn nghênh chiến. Đồng tử hàn băng tiết lộ Hồng Sam Tử chỉ là phân thân rồi liên thủ năm cao thủ vây đánh. Đại quân thứ ba giới ngoại gồm sáu vạn tu sĩ hơn mười bộ lạc tràn tới, tình thế tuyệt vọng. Vương Lâm lui về trước tu sĩ Vân Hải thét lên một tiếng kinh thiên động địa."},{"chuong":1430,"tieuDe":"Thất Bại!","tomTat":"Tu sĩ Vân Hải còn không tới một vạn, sĩ khí tan rã hoàn toàn, bỏ chạy tuyệt vọng trước đại quân giới ngoại hơn mười vạn người. Hồng Sam Tử một mình tử chiến sáu cao thủ bước thứ ba, Nam Vân Tử kiên trì không lùi vì đại ân Phong Tôn. Vương Lâm không nói một lời, một mình đứng giữa tinh không chặn toàn bộ đại quân — mở Thái Cổ Lôi Giới triệu lôi đình, tung hư hỏa Chu Tước, rút huyết kiếm tử chiến, diệt hơn hai ngàn tu sĩ giới ngoại nhưng nguyên lực và Cổ Thần lực cạn kiệt, toàn thân đầy vết thương. Hành động của hắn cảm hóa mấy ngàn tu sĩ Vân Hải đang bỏ chạy — bắt đầu từ một thanh niên Khuy Niết Sơ Kỳ, lần lượt tất cả dừng bước quay lại, bừng tỉnh chiến ý. Khai Thiên Phủ trong Phong Giới Đại Trận chém xuống giết năm nghìn tu sĩ giới ngoại. Vương Lâm hét gọi Phong Tôn, thần thức Phong Tôn trong ngọc bội bộc phát sức mạnh cuối cùng trong sinh mệnh, dung nhập Phong Giới Đại Trận rồi nhập Khai Thiên Phủ để chế phục. Khai Thiên Phủ thu nhỏ, khí tức Cổ Thần tăng gấp bội, Vương Lâm nhảy lên nắm lấy — là người đầu tiên cầm Khai Thiên Phủ kể từ khi nó dung nhập Phong Giới Đại Trận, tinh điểm Cổ Thần trên mi tâm xoay tròn, khí thể bộc phát sánh ngang lúc nhận truyền thừa Đạo Cổ."},{"chuong":1431,"tieuDe":"Nắm Lấy Khai Thiên Phủ!","tomTat":"Vương Lâm cầm lấy Khai Thiên Phủ, Cổ Thần lực vô biên từ búa chảy vào tinh điểm thứ tám vốn chưa thành hình, khiến nó bành trướng điên cuồng hấp thụ. Hắn hô hào mấy ngàn tu sĩ Vân Hải tử chiến, phát tiếng rống Cổ Thần chấn nhiếp hơn mười vạn tu sĩ giới ngoại sợ hãi lùi lại, khí thế được so sánh với chủ nhân Phong Giới trong đại chiến Phong Giới lần thứ hai. Hồng Sam Tử và Nam Vân Tử cầm chân các cao thủ bước thứ ba giới ngoại, nhưng Hồng Sam Tử bị thương từ trước do Tiên Phi đánh lén nên không giữ nổi tất cả, để lão tổ Hỏa Tước Tộc thoát ra lao tới tấn công Vương Lâm. Vương Lâm dùng Khai Thiên Phủ chém một búa chẻ đôi lão tổ Hỏa Tước Tộc từ đầu xuống, diệt nguyên thần, giết cao thủ bước thứ ba trong nháy mắt. Sau đó hắn xuyên qua thi thể, mang sát khí phóng thẳng về phía Vân Lạc Đại Ti khiến toàn bộ tu sĩ giới ngoại tái nhợt lùi lại, còn Vân Lạc cuống quýt lui, nhận ra cảnh tượng nàng từng tính toán ra đang ứng nghiệm vào chính mình. Mấy ngàn tu sĩ Vân Hải đồng thanh hô vang Phong Tôn vinh quang."},{"chuong":1432,"tieuDe":"Chôn Cất Không Có Người Thương Tiếc!","tomTat":"Sau khi Vương Lâm dùng Khai Thiên Phủ chém chết Lão tổ Hỏa Tước Tộc, chiến ý mười vạn quân giới ngoại sụp đổ. Hồng Sam Tử tuyên bố cuộc chiến không thể bại, lao vây khốn hàn y đồng tử, Nam Vân Tử ngăn tiên phi giới ngoại. Vương Lâm cầm Khai Thiên Phủ lao thẳng vào đại quân giới ngoại, dùng Hư hỏa thiêu chết tu sĩ cản đường, khoảng cách với Vân Lạc đại ti thu hẹp nhanh chóng. Hàn y đồng tử nhận ra tâm thần quân giới ngoại đang tan rã, gầm lệnh giết Phong Tôn, đánh văng Nam Chiếu Thượng Nhân và lão già Bạch Lặc tộc ra để chặn Vương Lâm. Nam Chiếu Thượng Nhân thi triển khói độc năm màu bổn mạng thành năm vòi rồng nhưng bị Vương Lâm triệu Thiên Hoàng Lô xuất ba giọt độc dịch nổ thành biển độc nuốt sạch, biển độc trùm lên hòa tan toàn thân Nam Chiếu, hồn phách bị thu vào Thiên Hoàng Lô. Lão già Bạch Lặc tộc hoảng sợ rút lui. Vương Lâm dung sáu giọt độc dịch còn lại lan tám hướng, mở khe không gian thả Văn thú tấn công, rồi lao tới Vân Lạc đại ti cách trăm trượng giơ Khai Thiên Phủ chém xuống."},{"chuong":1433,"tieuDe":"Nam Chiếu Vong","tomTat":"Vương Lâm vung Khai Thiên Phủ trên chiến trường Vân Hải tinh vực, phủ mang xuyên thấu hàng ngàn tu sĩ giới ngoại bảo vệ Vân Lạc đại ti, không gì ngăn cản. Khai Thiên Phủ chém nát huyết thuẫn bát giác của Vân Lạc rồi xuyên thấu thân thể, nhưng thân thể hóa thành búp bê vải — chỉ là phân thân. Vương Lâm thiêu cháy búp bê, dùng thần thông rút tơ tạo hắc động truy tìm bổn tôn, phóng Cực Cảnh dung hợp lôi hóa xuyên qua hắc động tấn công thẳng thánh địa truyền thừa Vân Lạc nằm trong tam đại cấm địa Trường Tôn hội ở Thái Cổ Tinh Thần giới ngoại. Cực Cảnh giáng xuống phá hủy đảo nhỏ, thiêu cháy hồ nước, làm sụp lầu các. Vân Lạc đọc quẻ tượng tổ tiên ứng nghiệm từ tam tượng đến lục tượng, lấy hài cốt sư tôn ra chắn nhưng hài cốt cũng vỡ. Thân thể vỡ tan, nguyên thần sụp đổ, nhưng hồn phách dung nhập cơn lốc do hài cốt hóa thành và biến mất — chưa chết hẳn. Trên chiến trường, biển độc và mấy vạn Văn thú tràn khắp tinh không, viện quân La Thiên gần 900 tu chân tinh và viện quân Triệu Hà đồng thời xuất hiện."},{"chuong":1434,"tieuDe":"La Thiên, Triệu Hà Động","tomTat":"Đại quân Triệu Hà do Tử Mộng dẫn đầu (mấy vạn nữ tu) cùng tu sĩ La Thiên do Lỗ Phu Tử dẫn đầu (hơn chín trăm tu chân tinh) tới chi viện giới nội, hợp lực với mấy ngàn tu sĩ Vân Hải sống sót. Vương Lâm tuyên bố ba cao thủ giới ngoại đã chết, phá vỡ hoàn toàn sĩ khí đối phương. Tử Mộng tiếp quản trận chiến với Tiên Phi thay Nam Vân Tử, hai bên ngang tài ngang sức; Tiên Phi hỏi vì sao tỉ tỉ của Tử Mộng không tới, Tử Mộng đáp sẽ sớm tới. Mỹ phụ trung niên Triệu Hà cùng Lỗ Phu Tử hỗ trợ Hồng Sam Tử giáp công hàn y đồng tử. Nam Vân Tử cùng Linh Động và Chu Cẩn rút về sửa chữa Phong Giới Đại Trận. Tu sĩ giới ngoại liên tiếp tử vong bởi độc hải, đàn Văn Thú và tia chớp Triệu Hà, từ hơn mười vạn giảm còn chưa tới tám vạn. Đại quân thứ ba gồm năm vạn tu sĩ và hai cao thủ Không Niết Trung Kỳ xuất hiện bên ngoài Phong Giới Đại Trận, Vương Lâm xông tới lỗ hổng hiện thân thể thật Thất Tinh Cổ Thần ngàn trượng, tuyên bố trừ khi hắn chết không ai bước vào giới nội. Hắn liên tiếp dùng Hư Hỏa thiêu mấy ngàn tu sĩ, lôi đình quét biển sấm sét, cuối cùng dồn toàn bộ Cổ Thần lực chém Khai Thiên Phủ bay thẳng về phía hai cao thủ bước thứ ba."},{"chuong":1435,"tieuDe":"Nữ Tu Triệu Hà","tomTat":"Vương Lâm vung Khai Thiên Phủ chém xuyên đại quân giới ngoại, chiếc búa phóng to ngàn vạn lần rạch một khe ngàn trượng, chém đứt tay hai cao thủ bước thứ ba và giết vô số tu sĩ, buộc đại quân thứ ba rút lui về Thái Cổ Tinh Thần. Hắn đứng trong lỗ hổng Phong Giới Đại Trận tuyên bố giết sạch mọi kẻ xâm nhập, dùng Hư hỏa và hơn mười lá cổ Tức Diệp phong ấn bao vây mấy vạn tu sĩ giới ngoại đã mắc kẹt bên trong, trong khi La Thiên, nữ tu Triệu Hà cùng mấy ngàn tu sĩ Vân Hải và đàn Văn Thú truy kích chém giết không ngừng. Lam Mộng Đạo Tôn — đứng đầu Thái Cổ Ngũ Tôn, tu vi Không Huyền đại viên mãn — xuất hiện yêu cầu Vương Lâm tha tu sĩ giới ngoại, nhắc lại ba lần ân tình giữa hai người và cảnh cáo lần thứ tư sẽ ra tay. Vương Lâm vái sâu đáp lễ nhưng không nhượng bộ, triệu trăm vạn cấm chế ngưng tụ thành khung ô khổng lồ khiến Phần Giới cổ Tán mở ra một phần, biển lửa diệt thế tràn ngập tinh không thiêu sạch tu sĩ giới ngoại, kết thúc đợt xâm lược thứ nhất với thương vong thê thảm cả hai bên. Sức sống trong cơ thể hắn tản ra nhập vào cổ Tán để chống đỡ, trước mắt hiện lên hình bóng con gái Lam Mộng mỉm cười buồn bã nói hãy quên giang hồ đi. Ngay khi trận chiến sắp dứt, sát khí đột ngột từ Thái Cổ Tinh Thần truyền tới — nam tử áo trắng Phong Dư, thủ đồ của Chưởng Tôn mang danh hiệu ngón cái, giương một cây cung nhắm thẳng mi tâm Vương Lâm qua lỗ hổng trận pháp chưa kịp khép, và Vương Lâm nhận ra cây cung ấy hắn đã từng nhìn thấy."},{"chuong":1436,"tieuDe":"Trận Chiến Kết Thúc","tomTat":"Vương Lâm nhận ra cây cung trong tay thanh niên áo trắng (thủ đồ của Chưởng Tôn) chính là bảo vật năm xưa bắn rơi mắt trái Đạo cổ, có nguồn gốc từ quê hương Đạo cổ, chỉ xếp sau Thiên Nghịch và Địa La Bàn. Hắn hồi tưởng cây cung từng bị thất thải đạo nhân lấy đi, nay lại ở tay thủ đồ Chưởng Tôn, nghi ngờ mối liên hệ giữa hai người. Cảm nhận nguy cơ sinh tử, Vương Lâm lập tức triệu bảy tinh điểm Cổ Thần trên mi tâm, khiến đầu Đạo cổ hiện ra phòng ngự. Thanh niên áo trắng buông dây cung, hơn nửa sức sống bị hấp thụ hóa thành mũi tên hư ảo nhũ bạc lao qua lỗ hổng Phong Giới Đại Trận, tiếng gào thét khiến vô số tu sĩ hai phe thất khiếu chảy máu, một số trọng thương chết tại chỗ. Hồng Sam Tử, Vân Nam Tử và các cao thủ đều ngừng chiến kinh sợ, trong khi Tiên Phi và nữ tu Tử Mộng nhận ra lai lịch cây cung, lộ vẻ sợ hãi không che giấu. Toàn bộ Phong Giới Đại Trận bao phủ khắp tinh không giới nội chấn động kịch liệt."},{"chuong":1437,"tieuDe":"Cây Cung Của Lý Quảng","tomTat":"Mũi tên thứ nhất từ cung cổ Lý Quảng xuyên qua đầu Đạo Cổ, Vương Lâm dùng hai tay Cổ Thần kẹp chặt nhưng bị ép hiện thân lùi ngàn trượng, phun bảy ngụm máu trọng thương. Hắn lùi vào khu vực Cổ Tức Diệp phóng sương đen hút sức sống tu sĩ giới ngoại bị phong ấn để bổ sung năng lượng. Thái A La — mãnh thú vốn bị Phong Tôn phong ấn — bất ngờ xuất hiện từ Vân Hải Tinh Vực xả thân chắn mũi tên thứ hai, dùng lá chắn vảy cầm cự ba nhịp thở rồi hai tay vỡ nát. Vương Lâm dùng ba nhịp thở đó triệu lửa diệt thế Phần Giới Cổ Tán dung hợp máu Cổ Thần hủy mũi tên thứ nhất, rồi cưỡng ép mở Cổ Tán gần ba phần phá mũi tên thứ hai nhưng dư lực vẫn đâm vào ngực, thân Cổ Thần héo thành bộ xương. Vương Lâm triệu huyết kiếm nhưng nhận ra huyết kiếm chỉ xuyên vật thực chất nên tự kìm không truy kích. Cổ Yêu phái phân thân cửu tinh tập kích nam tử áo trắng nhưng bị dụ vào bẫy, uy áp Chưởng Tôn Phong Dư từ Thái Cổ Tinh Thần giáng bàn tay khổng lồ bóp nát phân thân. Nam tử áo trắng tự xưng thủ đồ Chưởng Tôn Phong Dư, ném cung ra trước lỗ hổng Phong Giới Đại Trận với điều kiện ba cơ hội lấy, mỗi lần trả ba phần tu sĩ giới ngoại. Vương Lâm suy luận Phong Dư đang sợ hãi điều gì đó, muốn dùng cung dụ hắn ra ngoài đại trận."},{"chuong":1438,"tieuDe":"Cung Ở Nơi Này","tomTat":"Tiên Phi áo đỏ nhận ra mình bị biến thành quân cờ, phẫn nộ bỏ đi qua lỗ hổng Phong Giới Đại Trận vào Thái Cổ Tinh Thần, hàn y đồng tử cũng rút theo. Phong Dư khiêu khích tu sĩ giới nội không ai dám lấy cung, lỗ hổng đang thu hẹp thì bàn tay khổng lồ từ Thái Cổ Tinh Thần lại hiện ra xé toạc mấy trăm trượng. Toàn bộ cao thủ giới nội — Hồng Sam Tử, Nam Vân Tử, Triệu Hà, Tử Mộng, Lỗ Phu Tử, Thái A La, Linh Động Thượng Nhân, Chu Cẩn — cùng Vương Lâm (dùng quyền Đạo Cổ) và Cổ Yêu (cửu tinh yêu long) liên thủ phá nát bàn tay, Vương Lâm bị thương nặng tay phải. Chín tu chân tinh bốc cháy lao tới cây cung, ba chiếc đầu phá bàn tay tái sinh, lộ ra hư ảnh hắc bào Chưởng Tôn. Chưởng Tôn giao chiến với tu chân tinh, bị bốn chiếc nổ tung xé rách thân, dùng thuật Giếng Trăng phá tu chân tinh cuối cùng nhưng ấn ký ánh trăng bị thân ảnh bí ẩn phá. Chiến lão quỷ xuất hiện, tuyên bố năm xưa từng đánh bại Thái Cổ Ngũ Tôn, viết chữ Chiến phá ấn ký, tuyên bố cung thuộc Lý tộc và cất bước đi nhận cung, Chưởng Tôn kinh hãi bị xé lộ dung nhan."},{"chuong":1439,"tieuDe":"Chiến Lão Quỷ!","tomTat":"Chiến lão quỷ chụp lấy cây cung trôi giữa tinh không, dây cung lóe ánh sáng bảy màu rồi đứt ra, hóa thành vũ khí uy lực kinh khủng quất thẳng vào hắn. Chiến lão quỷ viết bảy chữ Chiến đều bị quật vỡ, phải phun chữ Chiến màu trắng mới chặn nổi. Hắn ném cây cung vào giới nội, tiết lộ Thất Thải Đạo Nhân đã chủ động phá vỡ Bách Vạn Tu Linh Ấn và đây là cơ hội cuối cùng, rồi rời đi. Chưởng Tôn lộ ngoại hình già nua kỳ dị với ấn ký trên mi tâm, nhìn Chiến lão quỷ thù hận ngợp trời nhưng không dám mở miệng, túm thủ đồ bỏ chạy. Sợi dây cung xông vào giới nội phá tan phong ấn Cổ Tức Diệp, quét sạch mấy vạn tu sĩ giới ngoại. Vương Lâm liều mình cầm cung nhưng tay phải vỡ tan, tay trái nắm được thì bị dây cung chém đôi thân thể. U Minh Thú vì sinh mệnh gắn liền Vương Lâm mà tỉnh giấc, phun ra cuồng phong màu vàng chưa tiêu hóa hủy diệt cả chiến trường — Phong Giới Đại Trận sụp đổ phạm vi lớn, điện chủ Thiên Phạt Điện bị cuồng phong tiêu diệt cả thân thể lẫn nguyên thần. U Minh Thú nuốt Vương Lâm cùng cây cung rồi tàng hình biến mất. Trận chiến thứ nhất kết thúc kỳ dị, để lại hố đen khổng lồ và dư âm tồn tại vạn năm."},{"chuong":1440,"tieuDe":"U Minh Thức Tỉnh","tomTat":"Sau trận chiến thứ nhất, giới ngoại Thái Cổ Tinh Thần chịu tổn thất nặng nề với mấy chục bộ lạc tử vong toàn bộ, hơn mười vạn tu sĩ chôn vùi, lão tổ Hỏa Tước Tộc, Nam Chiếu Thượng Nhân, điện chủ Thiên Phạt Điện đều tử vong. Chưởng Tôn hạ lệnh chuẩn bị trận chiến thứ hai, truyền hình dáng Vương Lâm cho toàn bộ tu sĩ giới ngoại và treo thưởng chưa từng có để giết hắn. Vân Hải Tinh Vực cũng tử thương thê thảm, chỉ còn mấy ngàn tu sĩ sống sót, tinh vực bất ổn với khe không gian rách khắp nơi. Yêu Tông, Quỷ Tông, Thần Tông dưới sự chỉ huy của tân tông chủ Mộc Băng Mi bày binh bố trận phòng thủ, Côn Hư phái một vạn tu sĩ do nữ tử áo lam bí ẩn chỉ huy đóng quân bên ngoài cơn lốc sương mù. Tên Phong Tôn Vương Lâm truyền khắp giới nội, được công nhận là người đứng đầu, nhưng hắn hoàn toàn biến mất. Tư Đồ Nam trong bi thương bỏ mặc tu luyện rồi cùng Chu Như rời Vũ Giới tìm huynh đệ, Thập Tam sớm nhất mang pho tượng Vương Lâm lên đường, đầu to và Lôi Cát cũng bỏ đi tìm chủ nhân. Đàn Văn Thú dung hợp độc hải gào thét tìm Vương Lâm khắp nơi, trong khi U Minh Thú tàng hình trốn trong khu vực đá vụn cực bắc Côn Hư Tinh Vực, bị dọa sợ vỡ mật, thà chết không chịu ra ngoài."},{"chuong":1441,"tieuDe":"Tìm Kiếm","tomTat":"Bên trong cơ thể U Minh Thú là Thất Thải Giới — một tinh không kỳ dị gần như không có sinh linh, chỉ có một tu sĩ bị nhốt lâu năm đến phát điên, tự xưng Tiểu Ngân Đạo Vương. Hắn phát hiện thi thể Vương Lâm rơi từ trên trời xuống tu chân tinh đã vỡ, sửng sốt bốn năm mới kéo về chỗ mình. Hắn liên tục tấn công thi thể bằng hàng loạt thần thông bí ẩn — Dịch Linh Ấn chính tông do Phong Tôn truyền, Phần Giới Cổ Tán, Thất Thải Thuật — tất cả nhìn hoành tráng nhưng không có uy lực thực tế. Hàng ngày hắn cho Vương Lâm uống máu tươi cực quý của mình, máu này xung đột dữ dội với sức mạnh Đạo Cổ trong cơ thể Vương Lâm, hai bên cắn nuốt nhau nhưng mơ hồ dung hợp, tạo ra biến đổi kỳ dị — Vương Lâm chính thức chuyển hóa từ phàm nhân thành tiên nhân. Dây cung đứt của cung Lý Quảng đâm sâu vào thân thể dần biến thành huyết mạch dung hợp, cung cảm nhận huyết mạch Vương Lâm tinh thuần hơn chủ nhân xưa gấp bội, phát tiếng hoan hô nhận chủ mới. Tu sĩ điên lảm nhảm nhắc Tiểu Hồng, ca ca, Cổ Quốc, cung Lý Quảng nhưng không nhớ rõ, bảo ca ca đừng tìm mình."},{"chuong":1442,"tieuDe":"Người Điên!","tomTat":"Vương Lâm tỉnh lại trong đau đớn, thân thể vẫn chỉ còn nửa người, máu của người điên lưu chuyển trong cơ thể chém giết với Cổ Thần lực rồi dần dung hợp vào xương cốt, biến đổi huyết mạch. Cây cung trong tay truyền tiếng hoan hô ấm áp, lần đầu dung hợp nhận chủ nhờ huyết mạch đang biến đổi — chỉ loại huyết mạch của tộc người điên mới khiến nó nhận chủ. Người điên thì thầm tự xưng bổn vương, nhắc tới ca ca, tiểu yêu nữ tên Phi Phi và Tiểu Hồng, rồi phẫn nộ vì thân thể Vương Lâm không kéo dài ra được, dùng ấn ký quỷ dị vỗ ngực phun máu vàng nồng đậm nhiều lần, cuối cùng cắn đầu lưỡi phun bổn mệnh huyết rồi ngất xỉu. Lượng máu khổng lồ cùng bổn mệnh huyết bộc phát uy áp áp chế cả Cổ Thần lực lẫn Đạo Cổ lực, máu cũ bị bức ra, tủy sống sản sinh máu mới mang khí tức cao quý tột đỉnh. Mắt trái Vương Lâm ngọn lửa chín màu biến thành lửa kim sắc, mắt phải lôi đồ và chín đạo sấm sét sụp đổ thành tia chớp kim sắc — kim sắc là màu sắc của tiên thật sự — hai mắt bộc phát uy áp khủng khiếp."},{"chuong":1443,"tieuDe":"Bổn Vương Nghỉ Thôi","tomTat":"Tiên huyết mạch từ người điên lưu chuyển toàn thân Vương Lâm, khiến lôi bổn nguyên hóa thành tiên lôi thật sự, hư hỏa hóa tiên hỏa, ba bổn nguyên sinh tử, nhân quả, chân giả tiến gần viên mãn — uy lực đạt mức ngay cả Tứ Đại Tiên Đế cũng chỉ như phàm nhân so với hắn. Tuy nhiên truyền thừa Đạo Cổ (Cổ Thần) và tiên huyết mạch bài xích lẫn nhau trong thân, nửa thân dưới dao động giữa hồi phục và tan vỡ, nguyên thần tách khỏi thân thể không thể tự chọn. Người điên tỉnh dậy nổi giận, cắn vai Vương Lâm, sai Tiểu Hồng tới Hình gia lấy đồ, rồi tự giật đứt cánh tay trái trong cơn phẫn nộ. Khi gắn cánh tay lại, ấn ký hình tròn tràn ngập khí tức sơ khai hiện ra, giúp hắn nhớ ra tam ấn tổ tiên Tiên Tộc. Người điên bấm quyết khiến tu chân tinh chấn động, rút ấn ký trên mi tâm mình đặt lên tinh điểm Cổ Thần trên mi tâm Vương Lâm, tuyên bố tam ấn tổ tiên biến thành thân thể bất diệt Tiên Tộc. Sức mạnh Cổ Thần trong thân Vương Lâm bộc phát phản kháng kinh thiên, đánh người điên bắn tung phun máu, trước khi ngất hắn nhớ ra ca ca dặn cấm truyền cho ba bộ tộc Cổ Quốc nhưng tự lừa bản thân. Cuối cùng Vương Lâm mở mạnh hai mắt tỉnh lại."},{"chuong":1444,"tieuDe":"Thân Thể Bất Diệt Của Tiên Tộc","tomTat":"Ấn ký tiên tổ hình tròn xuất hiện trên mi tâm Vương Lâm, kích hoạt huyết mạch tiên tộc sôi trào xung đột dữ dội với Đạo Cổ lực và Cổ Thần lực trong thân thể hắn. Bảy tinh điểm Cổ Thần lần lượt vỡ tan qua bảy lần toái tinh, mỗi lần thân thể chuyển đổi giữa Cổ Thần thể và Tiên Nhân Bất Diệt Thể trong thống khổ cực độ. Lần chuyển đổi thứ tám khi chưa kịp thành tinh điểm thứ tám cũng nổ, đệ nhị tổn trong tam tổn thất kiếp Cổ Thần xuất hiện do ấn ký tiên tổ dẫn dắt. Thân thể Vương Lâm hoàn toàn tan rã, máu thịt Cổ Thần dung nhập mặt đất đen, tiên thể nguyên thần bao phủ bầu trời vàng, tạo cảnh kim thiên hắc địa — người điên tỉnh lại nhận ra đó là đệ nhất tướng trong cửu khúc tam tướng giống khi tiên tổ giáng lâm. Hạt châu Thiên Nghịch tự phát hiện ra giữa hai hư ảnh Vương Lâm, xoay hai vòng hút trọn tiên nguyên và Đạo Cổ Cổ Thần, dung hợp thành thân Cổ Thần phát kim quang. Sau dung hợp, ấn ký tiêu tan, bảy tinh điểm tái hiện nhưng biến thành màu vàng, mắt trái kim hỏa, mắt phải tia chớp vàng. Vương Lâm phun máu rồi khoanh chân tĩnh tọa. Người điên mơ hồ nhận ra Thiên Nghịch là thứ ca ca đang tìm nhưng lại quên, gọi Vương Lâm là tiểu nương tử đòi cười."},{"chuong":1445,"tieuDe":"Kim Thiên Hắc Địa","tomTat":"Người điên tự xưng bổn vương, lảm nhảm mấy ngày kể chuyện Tiểu Hồng bên cạnh Vương Lâm đang thổ nạp. Vương Lâm hoàn thành dung hợp Tiên-Thần: thân Cổ Thần bên ngoài, nguyên tiên thay nguyên thần bên trong, hạt châu Thiên Nghịch ở lõi sâu nhất, nguyên lực biến mất hoàn toàn thay bằng tiên lực. Thân thể cường đại gấp mấy lần, tự đánh giá giết Không Niết hậu kỳ trong nháy mắt, toàn lực vượt cả Nam Chiếu Thượng Nhân, nhưng lực bài xích Tiên-Thần ngày càng mạnh khiến chỉ phát huy hai phần thực lực và có nguy cơ thân thể nổ tung bất cứ lúc nào. Ấn ký tiên tổ trên mi tâm hòa tan vào thân Thất Tinh Cổ Thần tạo tinh điểm vàng chưa từng có. Vương Lâm mở mắt tỏa kim quang, người điên nhận ra mắt vàng tộc mình nhưng chê nhạt màu, biểu diễn mắt vàng rực uy nghiêm rồi xì hơi mất phong thái. Vương Lâm bỏ kế hoạch ngưng luyện ma hồn, thay vào đó hóa giải huyết nhục thi thể Cổ Ma thành sáu ma tinh dung nhập mắt phải kết hợp kim quang bảy tinh điểm Cổ Thần. Người điên kinh ngạc nhận ra đó là tam đại vương tính cổ quốc, đồng thời phát hiện Vương Lâm có bất diệt thể vốn chỉ hắn và ca ca sở hữu, tuyên bố phải điều tra ai dám cho tu sĩ cổ quốc bất diệt thể tiên tộc."},{"chuong":1446,"tieuDe":"Cổ Quốc Tam Tính","tomTat":"Vương Lâm tỉnh dậy bên trong thế giới cơ thể U Minh thú, dành ba ngày chuyển lực bài xích vào sáu khối ma tinh trong mắt phải khiến chúng chuyển màu vàng, tạm trì hoãn nguy cơ nhưng không giải quyết triệt để. Hắn triệu cây cung Lý Quảng ra nhưng phát hiện dây cung đã đứt, không thể sử dụng. Người điên thấy hắn tỉnh liền tức giận hỏi ai truyền bất diệt thể của tiên tộc, nhưng chỉ vài giây sau quên sạch, chuyển sang gọi hắn là tiểu nương tử và tự xưng bổn vương. Vương Lâm dùng cuồng phong đá người điên đi mười sáu lần nhưng người điên lại thích thú, thả hắc viên ra thi gầm thét với người điên cũng thua. Trong lúc yên tĩnh suy tư, Vương Lâm nhận ra cần đại thành ba bổn nguyên sinh tử, nhân quả, thật giả để hóa giải lực bài xích — năm đạo đại thành sẽ mở không môn bước vào bước thứ ba, nhưng hắn vẫn còn thiếu mấy đạo quả. Cuối chương, người điên thi triển Dịch Linh Ấn vô cùng chính tông — giơ tay điểm bầu trời ngưng tụ bàn tay khổng lồ uy nghiêm giáng xuống — khiến Vương Lâm chấn động, coi đây là cơ may lớn lao sau huyết mạch tiên nhân."},{"chuong":1447,"tieuDe":"Thần Thông","tomTat":"Người điên thi triển Dịch Linh Ấn hoàn chỉnh trước mặt Vương Lâm, phiên bản có vân tay lòng bàn tay rõ ràng kèm gợn sóng lực chấn động giống thuật mạnh nhất Huyền Vũ tộc. Vương Lâm nhận ra bản Dịch Linh Ấn của bản thân thiếu khẩu quyết truyền thừa nên càng lớn càng mất khống chế, còn bản Thủy Đạo Tử tuy ổn định hơn nhưng vân tay vẫn kém rõ. Vương Lâm tự đánh ra hố mấy vạn trượng trên mặt đất tu chân tinh rồi thách thức người điên làm tương tự, liên tục dùng vẻ khinh miệt và giả khiếp sợ để khích tướng. Người điên nổi giận thi triển hàng trăm lần suốt bảy canh giờ, trong khi Vương Lâm toàn tâm quan sát dùng ngộ tính suy diễn. Vương Lâm ngộ ra cơ chế cốt lõi của Dịch Linh Ấn là nô dịch thiên địa nguyên lực hóa linh hồn rồi tiên lực tràn vào thành chưởng ấn, nhưng vẫn thiếu khẩu quyết truyền thừa tuyệt mật. Người điên kiệt sức rốt cục tạo được hố ngang bằng, tự hào hỏi thần thông có lợi hại không, tiết lộ ca ca dặn không được truyền thụ cho ai. Vương Lâm tiếp tục vu người điên dùng hai loại thần thông khác nhau, khiến người điên oan khuất gần khóc."},{"chuong":1448,"tieuDe":"Hơi Vô Sỉ Rồi","tomTat":"Vương Lâm dùng mưu khích người điên oan ức bật khóc, khiến hắn đọc toàn bộ khẩu quyết Dịch Linh Ấn chính tông để chứng minh mình không nói dối. Vương Lâm thi triển thành công, nhận ra đây là đạo thuật chứ không phải thần thông, ba luồng khí tức hóa ba chưởng đồng thời giết sạch thể, thần, hồn, uy lực vượt xa bản không hoàn chỉnh của Thủy Đạo Tử. Cảm thấy tội lỗi, Vương Lâm lập lời thề bảo vệ người điên, ân oán phân minh. Sau đó dùng đan dược thơm dụ người điên biểu diễn thêm ba đạo thuật mạnh mẽ: bản gốc Phần Giới Cổ Tán với ô đã mở sẵn, thuật bắn tên tư thế Lý Quảng có thể bắn nát thiên địa, thuật thương bảy màu ẩn chứa lực lượng tâm tình vượt xa hư hỏa. Vương Lâm chỉ quan sát chứ chưa có khẩu quyết ba thuật này. Cuối cùng Vương Lâm nhớ ra người điên sợ U Minh thú, triệu hồi hồn ảnh khổng lồ của nó. Người điên lập tức sụp đổ vẻ đắc ý, hoảng sợ run rẩy kêu mình không ăn được."},{"chuong":1449,"tieuDe":"Kinh Hãi","tomTat":"U Minh thú nhận ra người điên chính là kẻ năm xưa từng khiến nó kinh hãi, nhưng nhờ có Vương Lâm bên cạnh, tính cách dữ tợn chiếm ưu thế, lao tới hù dọa người điên vỡ mật. Vương Lâm nảy kế dùng thần niệm điều khiển U Minh thú giả vờ truy đuổi, cố ý phun máu giả bị thương, ôm người điên lùi lại diễn cảnh sống còn. Người điên trong hoảng sợ cực độ chủ động truyền thụ ba thần thông cho Vương Lâm: Phần Giới cổ Tán, Toái Thiên Nhất Cung (Lý tộc), thuật bảy màu. Vương Lâm so sánh và xác nhận khẩu quyết Phần Giới cổ Tán chuẩn xác hơn bản Chu Tước đời đầu học trộm, nhưng thi triển thử thì sụp đổ ngay, cần bế quan tiềm tu nhiều năm. Cuối cùng Vương Lâm dùng sương mù che mắt, giả vờ thu phục U Minh thú. Người điên kinh ngạc cuồng nhiệt, nhận định Vương Lâm là cao nhân, nhắc lời ca ca rằng trong tinh không cao nhân không ít, tha thiết xin bái Vương Lâm làm sư phụ. Vương Lâm trong lòng cảm giác có lỗi ngày càng đậm, tự thề có ân tất báo, nhất định đền bù gấp bội cho người điên sau này."},{"chuong":1450,"tieuDe":"Nhận Ta Làm Đồ Đệ Đi","tomTat":"Tại tu chân tinh bên trong thế giới U Minh thú, người điên bất ngờ quỳ dập đầu bái Vương Lâm làm sư phụ, thề lấy tiên tổ không phản bội sư môn, vỗ mi tâm phóng lực thề ước dung nhập vào cơ thể Vương Lâm. Vương Lâm thu U Minh thú chỉ bằng một vỗ tay khiến thú tiêu tán vô ảnh, rồi dụ người điên tiết lộ thần thông — người điên buột miệng nhắc đến Tiên Chi Cửu Tuyệt, nói ca ca chỉ hiểu được Thất Tuyệt, trong cơ thể có lời thề cấm nói chi tiết kẻo chịu tiên phạt. Vương Lâm hẹn ba ngày rời đi, tính toán phải trấn áp lực bài xích Huyền Lương Kiếm và đạt đạo quả. Người điên đòi học thần thông, Vương Lâm lần lượt thi triển toàn bộ thần thông cả đời — Hô Phong, Hoán Vũ, Rải Đậu Thành Binh, Băng Sơn, Phiên Thiên Ấn, Quang Ảnh Thuẫn, Dung Hợp, Lực Tàn Dạ, cửa đá tuế nguyệt — tất cả đều bị người điên khinh thường chê sạch. Cuối cùng Vương Lâm thi triển Dẫn Lực Thuật — thần thông đầu tiên hắn học trong đời — người điên lại mê mẩn, học gần như tức thì từ ngọc giản, điều khiển trên vạn hòn đá tạo trận chiến giả. Ba ngày sau, Vương Lâm mở mắt, kim quang ẩn đi, dẫn người điên rời tu chân tinh biến mất trong thiên địa."}];
